(window.WISE_WORLD_Q = window.WISE_WORLD_Q || {}).id = [
  { id:1, topic:"Gizi seimbang", emoji:"🍱",
    question:"Mengapa penting makan beragam jenis makanan secara seimbang, seperti nasi, daging, dan sayur?",
    choices:["Karena perut cepat kenyang","Karena tiap makanan punya peran berbeda: ada yang menjadi energi untuk menggerakkan tubuh, ada yang membentuk otot dan tulang, dan ada yang menjaga kondisi tubuh","Karena makan banyak membuat lari lebih cepat","Karena makanannya terlihat berwarna-warni dan cantik"],
    answerIndex:1,
    explanation:"Setiap makanan menyimpan kekuatan penting berbeda yang disebut 'gizi'. Misalnya, nasi, roti, dan umbi-umbian menjadi 'energi yang menggerakkan tubuhmu', seperti gerobak yang butuh bahan bakar dan hewan pekerja yang butuh pakan. Daging, ikan, dan kacang-kacangan menjadi 'bahan yang membentuk otot, darah, dan tulangmu'. Lalu, sayur dan buah menjadi 'perisai yang melindungi tubuhmu dari penyakit dan menjaga kondisinya'. Jika salah satu saja kurang, kamu bisa kehilangan tenaga, lebih mudah sakit, atau berhenti tumbuh besar dan kuat. Makan beragam jenis makanan itu seperti membentuk tim terkuat di dalam tubuhmu sendiri." },
  { id:2, topic:"Tidur dan otak", emoji:"😴",
    question:"Tidur yang cukup di malam hari sangat baik untuk otakmu. Hal baik apa yang dilakukannya?",
    choices:["Otakmu merapikan kejadian dan ilmu dari hari itu dengan rapi dan menyimpannya sebagai ingatan","Selama kamu tidur, otakmu lenyap sepenuhnya","Kamu tidak perlu sarapan keesokan harinya","Kamu mendapat mainan yang kamu inginkan di dalam mimpi"],
    answerIndex:0,
    explanation:"Selama seseorang tidur, otak tidak hanya beristirahat. Ia mengambil sejumlah besar informasi dari hari itu — apa yang kamu lihat, apa yang kamu alami sehari-hari, hal baru yang diajarkan kepadamu — dan menatanya di dalam kepalamu ke dalam laci-laci seperti 'ini ingatan penting' dan 'ini ilmu yang diperlukan', merapikan semuanya. Jika kamu tidak tidur nyenyak, waktu untuk penataan ini tidak cukup, sehingga kamu bisa lupa apa yang susah payah kamu pelajari, atau kepala terasa kabur dan tak bisa berkonsentrasi keesokan harinya. Untuk menjadi lebih mahir dalam belajar dan juga bekerja, tidur malam benar-benar penting sebagai waktu perawatan otak." },
  { id:3, topic:"Kekuatan sarapan", emoji:"🍞",
    question:"Jika kamu tidak sarapan setelah bangun, apa yang terjadi pada tubuh dan otakmu sepanjang pagi?",
    choices:["Tubuhmu menjadi lebih ringan dan kamu melompat lebih tinggi dari biasanya","Otakmu kekurangan energi (glukosa), sehingga kepalamu tidak bekerja baik, kamu jadi mudah marah, dan kehilangan tenaga","Matamu melihat lebih jelas","Tidak ada yang berubah"],
    answerIndex:1,
    explanation:"Setelah tidur nyenyak semalaman, otak dan tubuhmu yang segar terbangun hampir seperti baterai yang habis, dengan energi yang kosong. Untuk bekerja, otak butuh energi bernama 'glukosa', tetapi tubuh tidak bisa menyimpannya banyak. Karena itu, jika kamu mulai bergerak tanpa sarapan, tidak ada bahan bakar yang sampai ke otakmu: kata-kata penting tidak masuk ke kepalamu, dan kamu bisa mudah marah karena hal kecil bahkan bertengkar dengan teman atau keluarga. Sarapan adalah 'sakelar hati' yang membuatmu memulai hari dengan penuh tenaga dan senyuman." },
  { id:4, topic:"Bujukan orang asing", emoji:"🚶",
    question:"Seorang asing berkata kepadamu, 'Ibumu kecelakaan dan dibawa ke rumah sakit, jadi ikut aku ke tempat yang jauh.' Apa yang kamu lakukan?",
    choices:["Karena kamu cemas pada keluargamu, kamu buru-buru ikut orang itu","Jangan pernah ikut. Tinggalkan tempat itu segera dan larilah ke tempat aman yang ramai, seperti pasar atau lapangan, lalu minta tolong pada orang dewasa di dekatmu","Kamu berjalan bersama orang itu untuk mencari rumah sakit","Kamu berdiri diam di tempat dan menangis"],
    answerIndex:1,
    explanation:"Ini adalah 'kebohongan' yang dipakai orang jahat untuk menipu anak-anak dan membawanya pergi (kejahatan seperti penculikan dan kerja paksa). Bila ada anggota keluarga yang benar-benar terluka parah, orang yang kamu percaya — orang dari desamu, seorang guru, atau kerabat — akan berbicara langsung denganmu. Orang asing tidak akan pernah datang menjemputmu sendirian. Sekhawatir atau sepanik apa pun kamu, peganglah teguh aturan: 'jangan pernah ikut orang asing'. Lalu, tinggalkan tempat itu segera dan larilah ke tempat aman yang ramai dan suaramu bisa terdengar, seperti pasar atau lapangan, dan minta tolong pada orang-orang dewasa di sekitarmu." },
  { id:5, topic:"Berteriak minta tolong", emoji:"📢",
    question:"Saat kamu berjalan di luar, seorang asing memegang lenganmu dengan paksa atau mencoba membawamu pergi. Apa yang kamu lakukan?",
    choices:["Kamu takut membuatnya marah, jadi kamu menurut dengan diam","Berteriaklah dari dasar perut 'Tolong! Kebakaran!', meronta dan melawan, lalu berlari sekuat tenaga ke arah tempat yang ramai","Kamu berjongkok di tempat dan menutup mata","Kamu bertanya padanya, 'Kita mau ke mana?'"],
    answerIndex:1,
    explanation:"Ketika kamu hampir berada dalam bahaya, diam karena takut membuat orang di sekitar tidak menyadarinya, dan keadaan menjadi sangat berbahaya. Orang jahat paling membenci 'suara keras' dan 'diperhatikan orang lain sehingga kejahatannya ketahuan'. Jika lenganmu dipegang, jangan malu: berteriaklah dari dasar perut 'Tolong!' dan 'Kebakaran!', kata-kata yang membuat semua orang menoleh. Lalu meronta untuk melepaskan tanganmu dan larilah sekuat tenaga ke tempat yang ramai. Mengeluarkan suara adalah senjata ampuh untuk mengirim SOS ke dunia di sekitarmu." },
  { id:6, topic:"Menyeberang jalan", emoji:"🚸",
    question:"Saat menyeberangi jalan yang dilalui mobil, motor, atau pedati kuda, mana cara yang benar untuk menyeberang dengan aman?",
    choices:["Langsung berlari buru-buru tanpa memastikan apakah ada kendaraan yang datang","Berhenti dahulu, perhatikan baik-baik ke kanan dan ke kiri, lalu menyeberang hanya setelah memastikan kendaraan yang mendekat sudah lewat sepenuhnya atau berhenti","Tutup mata, hitung sampai 10, lalu menyeberang","Hanya menunggu orang lain menyeberang"],
    answerIndex:1,
    explanation:"Saat menyeberang jalan, sangat berbahaya berasumsi 'pasti pengemudi melihatku dan berhenti'. Pengemudi mungkin sedang melihat ke arah lain, atau mungkin tidak melihatmu. Saat menyeberang, selalu pijakkan kakimu kuat-kuat di tanah dan berhenti, lalu lihat ke kanan dan ke kiri berkali-kali. Kemudian tunggu kendaraan yang mendekat lewat sepenuhnya, atau pastikan ia berhenti dengan jelas tepat di depanmu dan pengemudi bisa melihatmu, sebelum menyeberang lurus dengan aman. Kebiasaan memeriksa dengan matamu sendiri melindungi nyawamu." },
  { id:7, topic:"Jangan menerobos tiba-tiba", emoji:"🛑",
    question:"Mengapa kamu SAMA SEKALI TIDAK BOLEH tiba-tiba menerobos ke depan mobil, motor, atau pedati yang sedang melaju?",
    choices:["Karena kecepatan kendaraan akan bertambah lagi","Karena kendaraan yang berat tidak bisa berhenti mendadak seketika, meski pengemudi mengerem panik (jarak pengereman)","Karena warna kendaraan akan berubah","Karena orang yang berlari di belakang akan marah"],
    answerIndex:1,
    explanation:"Mobil, pedati, atau motor yang sedang melaju tidak bisa berhenti mendadak di tempat pada saat pengemudi menginjak rem, sekeras apa pun usahanya. Karena dorongan berat dan kecepatannya (kelembaman), ia pasti terus maju beberapa meter sejak rem mulai bekerja sampai benar-benar berhenti. Karena itu, jika kamu menerobos tepat di depan kendaraan, ia akan menabrakmu sekeras apa pun usaha pengemudi, menyebabkan kecelakaan mengerikan dengan luka parah atau hilangnya nyawa. Jangan pernah lupakan aturan ilmiah bahwa kendaraan tidak bisa berhenti mendadak." },
  { id:8, topic:"Air dan sengatan panas", emoji:"💧",
    question:"Pada hari panas, saat bermain di luar, mengapa kamu harus minum air bahkan sebelum merasa haus?",
    choices:["Karena minum air setelah haus membuat sakit perut","Karena saat otakmu merasa haus, air di dalam tubuhmu sudah banyak berkurang: itu tanda kamu mulai terkena sengatan panas","Karena jika tidak cepat minum, airnya akan basi","Karena minum banyak air membuat tempat teduh lebih sejuk"],
    answerIndex:1,
    explanation:"Saat panas, tubuhmu berkeringat untuk menurunkan suhunya. Pada saat itu, air dan garam terus hilang dari dalam tubuhmu sedikit demi sedikit. Anehnya, meski air di tubuhmu sudah turun ke tingkat berbahaya, perlu sedikit waktu sebelum otakmu merasa haus. Artinya, ketika kamu merasa haus, tubuhmu sudah mengirim SOS. Jika dibiarkan, kamu terkena sengatan panas: kepala sakit, pusing, dan kamu bisa pingsan. Pada hari panas, kebijaksanaan menjaga tubuh tetap aman adalah menetapkan waktu dan minum sedikit air meski tidak haus." },
  { id:9, topic:"Layar dan mata", emoji:"📱",
    question:"Jika kamu menatap ponsel atau layar dari dekat, atau di tempat gelap, dalam waktu lama, apa dampak buruknya bagi tubuhmu?",
    choices:["Matamu tiba-tiba menjadi lebih kuat dan bisa melihat jauh bahkan di gelap","Otot matamu terus tegang dan lelah, sehingga penglihatanmu menurun, kamu sakit kepala, dan tidak bisa tidur di malam hari","Pendengaranmu jadi berkurang","Tidak ada yang berubah"],
    answerIndex:1,
    explanation:"Ketika seseorang menatap sesuatu dari dekat, ia mengencangkan otot kecil di dalam mata untuk memfokuskan pandangan. Jika kamu terus menatap layar terang dari dekat di tempat gelap, otot ini bekerja tanpa istirahat dan akhirnya seperti nyeri otot parah. Jika ini berlanjut, ia menyebabkan pemandangan dan tulisan yang jauh terlihat buram. Selain itu, cahaya kuat dari layar menipu otak supaya mengira 'sekarang siang!', sehingga kamu sulit tidur di malam hari dan kesehatanmu terganggu. Saat menatap layar, jaga sekitarmu tetap terang, dan sesekali pandanglah sesuatu yang jauh untuk mengistirahatkan mata." },
  { id:10, topic:"Mencegah gigi berlubang", emoji:"🦷",
    question:"Jika kamu makan camilan dan makanan manis sepanjang hari tanpa menetapkan waktu, mengapa gigimu lebih mudah berlubang?",
    choices:["Karena makan yang manis mengubah gigimu menjadi cokelat lembek","Karena selama ada gula di mulutmu, kuman gigi terus menghasilkan 'asam' sepanjang waktu, sehingga gigimu lebih lama terlarut","Karena gigimu kaget lalu copot","Karena terlalu banyak camilan membuat rahangmu lelah"],
    answerIndex:1,
    explanation:"Ketika kamu makan atau ngemil, kuman gigi di mulutmu memakan gula dari sisa makanan dan membuat 'asam'. Karena asam ini, sebenarnya gigi semua orang sedikit terlarut setelah makan. Tetapi setelah beberapa waktu, kekuatan 'air liur' di mulutmu memperbaiki gigi yang terlarut menjadi seperti semula dan bersih. Jika kamu terus mengemil tanpa menetapkan waktu, mulutmu selalu penuh asam dan kotor, dan air liur tidak punya waktu memperbaiki gigimu. Akibatnya, gigimu berlubang. Kebijaksanaannya adalah makan camilan pada waktu tertentu dan berkumur setelah selesai." },
  { id:11, topic:"Keringat dan kedinginan", emoji:"💦",
    question:"Saat kamu bergerak penuh semangat di luar dan banyak berkeringat, apa yang terjadi jika kamu tetap memakai baju basah?",
    choices:["Saat mengering, keringat tiba-tiba mengambil panas dari tubuhmu, sehingga kamu kedinginan, lebih mudah masuk angin, dan kulitmu gatal","Bajumu menjadi lebih kuat","Tubuhmu menjadi semakin hangat","Tidak ada yang berubah"],
    answerIndex:0,
    explanation:"Keringat adalah air yang keluar dari tubuhmu untuk 'menurunkan' suhu yang terlalu tinggi. Berkat keringat yang membawa panas kulitmu saat menguap ke udara, kita terhindar dari sengatan panas. Tetapi jika kamu tetap memakai baju basah bahkan setelah berhenti bergerak, panas tubuhmu terus terambil lama setelah keringat kering, dan kali ini tubuhmu menjadi terlalu dingin: kekebalanmu (kekuatan melawan penyakit) menurun dan kamu masuk angin. Selain itu, jika kotoran keringat tetap menempel di kulit, kulitmu iritasi dan gatal. Saat banyak berkeringat, penting untuk mengelapnya bersih dan berganti baju." },
  { id:12, topic:"Racun di alam", emoji:"🍄",
    question:"Di hutan atau di tepi jalan, kamu menemukan jamur atau buah tumbuhan dengan warna yang sangat indah. Apa yang harus kamu lakukan?",
    choices:["Karena terlihat lezat, kamu menggigit sedikit untuk mencicipi","Jangan pernah memasukkannya ke mulut. Tumbuhan yang tidak dikenal bisa memiliki racun kuat yang membahayakan nyawamu","Kamu membawanya pulang dan menjadikannya bahan sup","Kamu menyimpannya di saku sebagai jimat"],
    answerIndex:1,
    explanation:"Di antara tumbuhan dan jamur di alam, banyak yang, seindah dan selezat apa pun terlihat, mengandung zat yang sangat beracun bagi tubuh manusia. Dahulu kala, orang belajar mana yang aman dan mana yang berbahaya dari banyak kegagalan, dan mewariskannya sebagai pengetahuan. Tumbuhan yang belum kamu ketahui 100% aman tidak boleh sekali-kali dimasukkan ke mulut. Memakannya sedikit saja bisa menyebabkan muntah hebat dan sakit perut, dan dalam kasus terburuk merenggut nyawamu. Mencintai alam itu penting, tetapi untuk hal yang tidak kamu ketahui dengan benar, peganglah kehati-hatian bijak 'jangan disentuh, jangan dimakan'." },
  { id:13, topic:"Matahari dan sinar UV", emoji:"☀️",
    question:"Jika kamu terus terpapar sinar matahari musim panas yang kuat (sinar ultraviolet) tanpa berbuat apa-apa, apa yang terjadi pada kulitmu?",
    choices:["Kulitmu menjadi keras seperti besi dan tidak bisa terluka","Energi kuat matahari membuat kulitmu seperti dalam keadaan luka bakar: memerah, bengkak, dan perih, dan penghalang kulitmu rusak","Kulitmu menjadi putih dan bersinar","Kamu tidak lagi merasa lapar"],
    answerIndex:1,
    explanation:"Sinar matahari juga punya efek baik, seperti membantu membuat vitamin di dalam tubuh kita, tetapi sekaligus mengandung sinar kuat bernama 'sinar ultraviolet' yang merusak sel-sel kulitmu. Jika kamu terus terpapar matahari musim panas yang kuat dengan kulit telanjang, kulitmu membengkak memerah, dan menjadi luka bakar yang perih dan sangat sakit sampai kamu tidak bisa mandi. Ini bukti bahwa penghalang kulitmu rusak dan menjerit. Saat beraktivitas di luar, lindungi kulit berhargamu dari serangan matahari dengan memakai topi dan memilih tempat teduh sebisa mungkin." },
  { id:14, topic:"Postur yang benar", emoji:"🪑",
    question:"Jika kamu membungkukkan punggung dengan postur buruk dalam waktu lama, hal buruk apa yang terjadi pada tubuhmu?",
    choices:["Dengan punggung membungkuk, lebih banyak darah ke kepala dan kamu jadi lebih pintar","Paru-parumu tertekan dan napasmu menjadi dangkal, sehingga oksigen tidak sampai ke otakmu dan konsentrasimu menurun, serta tulang belakang dan pinggangmu menjadi bengkok dan sakit","Kakimu tumbuh semakin panjang","Perutmu lebih mudah bermasalah"],
    answerIndex:1,
    explanation:"Jika kamu mempertahankan postur bungkuk dengan punggung melengkung, 'paru-paru' di dalam dadamu tergencet. Maka jumlah udara yang bisa kamu hirup sekaligus berkurang dan napasmu menjadi dangkal. Karena manusia menghirup 'oksigen' dari udara untuk menggerakkan otak dan tubuh, ketika oksigen kurang, kamu cepat mengantuk, konsentrasimu menurun, dan kamu jadi mudah marah. Selain itu, beban berlebihan menekan tulang belakang dan pinggang yang menopang tubuhmu, dan tubuhmu mulai sakit. Menegakkan panggul dan duduk dengan punggung lurus adalah postur dasar untuk menjalankan otakmu dengan tenaga penuh." },
  { id:15, topic:"Aturan minum obat", emoji:"💊",
    question:"Saat kamu minum obat yang diberikan orang dewasa di rumah, apa janji penting yang wajib kamu patuhi?",
    choices:["Jika tidak terlihat enak, kamu memutuskan sendiri untuk berhenti meminumnya","Selalu minum dalam takaran yang benar pada waktu yang ditentukan. Ini bukan permen, jadi minum berlebihan menjadi racun bagi tubuhmu","Jika obat teman terlihat manjur, kamu minta sebagian dan meminumnya","Kamu menelannya sekaligus dengan jus, bukan air"],
    answerIndex:1,
    explanation:"Obat adalah 'zat khusus berkekuatan besar' yang mengalahkan kuman penyakit di dalam tubuhmu atau mengembalikan kondisi tubuhmu. Tetapi jika kamu minum dua kali lipat takaran sekaligus karena ingin cepat sembuh, atau memakannya banyak seperti permen, kekuatan besar itu malah berubah menjadi racun mematikan yang menyerang tubuh dan organmu sendiri. Selain itu, minum obat orang lain, yang dibuat sesuai tubuh orang itu, sama sekali dilarang, karena tidak cocok untuk tubuhmu dan menyebabkan kecelakaan serius. Obat adalah perisai yang harus selalu kamu gunakan dengan benar, bersama orang dewasa, mematuhi takaran dan aturan yang tertulis pada petunjuk." },
  { id:16, topic:"Keselamatan benda tajam", emoji:"✂️",
    question:"Saat kamu memakai gunting atau pisau (benda tajam) untuk prakarya atau pekerjaan, mana cara yang benar memegang dan memakainya agar tidak terluka?",
    choices:["Meletakkan tangan satunya tepat di samping arah laju mata pisau, lalu memotong","Tidak pernah meletakkan tangan atau jarimu di arah laju mata pisau, dan tidak mengarahkan mata pisau ke orang","Mengayunkannya sekuat tenaga agar tajam memotong","Membawanya di saku dengan mata pisau terbuka"],
    answerIndex:1,
    explanation:"Benda tajam seperti gunting dan pisau kecil adalah alat luar biasa yang bisa memotong dengan mudah, tetapi satu kesalahan saja membuatnya menjadi senjata berbahaya yang mengiris dalam kulit dan dagingmu sendiri. Saat memakai benda tajam, letakkan tangan satunya yang menahan benda di 'tempat aman yang, sekalipun tanganmu tergelincir dan mata pisau melesat ke arah itu, sama sekali tidak akan mengenainya'. Jika kamu bisa memperkirakan ruang dan tidak meletakkan tubuhmu atau tubuh orang lain di jalur alat, kamu tidak akan terluka parah meski tanganmu tergelincir. Kuasailah kekuatan alat dengan benar dan gunakan dengan aman." },
  { id:17, topic:"Tersengat listrik", emoji:"⚡",
    question:"Apa yang terjadi jika kamu memasukkan kawat logam atau peniti ke lubang stopkontak listrik di rumah atau gedung?",
    choices:["Dari stopkontak menyembur air bersih","Listrik yang sangat kuat yang mengalir di dalam tembok masuk ke tubuhmu dalam sekejap dan menyebabkan luka bakar parah atau menghentikan jantungmu (tersengat listrik)","Hanya seluruh listrik rumahmu padam, dan selesai","Tidak terjadi apa-apa"],
    answerIndex:1,
    explanation:"Jauh di dalam lubang stopkontak pada tembok gedung mengalir, 24 jam sehari, listrik yang sangat kuat dan berbahaya untuk menjalankan televisi dan mesin di seluruh rumah. Listrik punya sifat sangat mudah melewati logam, seperti besi dan kawat. Jika kamu memasukkan kawat atau garpu ke lubang stopkontak, listrik di dalam tembok merambat melalui logam itu dan membanjiri tubuhmu dalam sekejap. Ini disebut 'tersengat listrik'. Listrik kuat memberi kerusakan besar pada tubuh dan jantung manusia, dan bisa merenggut nyawamu. Kamu sama sekali tidak boleh memasukkan apa pun ke lubang stopkontak." },
  { id:18, topic:"Tempat berbahaya", emoji:"🕳️",
    question:"Mengapa kamu tidak boleh mendekati 'tempat berbahaya' yang tidak ada orang dewasa, seperti sumur dalam, tebing yang runtuh, atau reruntuhan bangunan tua?",
    choices:["Karena di sana bajumu akan kotor","Karena jika kamu kebetulan jatuh ke lubang atau tertimbun longsoran, tak seorang pun bisa menyadarinya dan kamu tak bisa minta tolong","Karena di sana ada harta tersembunyi","Karena ada hantu yang keluar"],
    answerIndex:1,
    explanation:"Di dunia ada banyak tempat berbahaya yang sekilas tampak seperti tempat bermain yang menyenangkan, tetapi yang dengan satu langkah salah bisa merenggut nyawamu. Di sekitar sumur dalam, di atas tebing yang runtuh, atau di reruntuhan tua, tanah di bawah kakimu bisa tiba-tiba ambruk. Yang paling menakutkan adalah, jika kecelakaan terjadi di tempat tanpa satu pun orang dewasa, tak seorang pun menyadari kamu terjebak di sana, dan kamu tak bisa diselamatkan saat air dan makananmu habis. 'Kebijaksanaan memperkirakan risiko' — tidak pernah mendekati tempat berbahaya sejak awal — itulah yang paling pasti melindungi nyawamu sendiri." },
  { id:19, topic:"Tanda demam", emoji:"🤒",
    question:"Ketika tubuhmu menggigil dan terasa dingin (meriang), itu pertanda apa yang akan terjadi di dalam tubuhmu?",
    choices:["Pertanda suhu ruangan tiba-tiba turun","Karena kuman masuk ke tubuhmu, itu pertanda otakmu akan menaikkan suhu tubuhmu dengan tajam (membuat demam) dan mulai berperang untuk membakar kuman","Pertanda tubuhmu berubah menjadi es","Pertanda makananmu selesai dicerna"],
    answerIndex:1,
    explanation:"Ketika sekitarmu hangat namun hanya kamu yang merasa menggigil, itu bukti bahwa kuman atau virus, seperti flu, telah menyerbu tubuhmu. Tim pertahanan (kekebalan) tubuhmu mencoba menaikkan suhu tubuhmu dengan sengaja sampai tinggi, untuk mengalahkan kuman yang lemah terhadap panas. Pada tahap persiapan 'aku akan menaikkan panas dan berperang!' ini, otak salah mengira lingkungan dingin dan mencoba membuat panas dengan menggigilkan tubuhmu, sehingga kamu merasa menggigil. Ketika tanda ini muncul, kebijaksanaan yang benar adalah segera memakai baju hangat, berbaring, mengistirahatkan tubuhmu, dan mendukung perjuangan tim pertahananmu." },
  { id:20, topic:"Bahaya bercanda kasar", emoji:"🤕",
    question:"Saat bermain dengan teman, mengapa salah mendorong mereka keras dari belakang sambil bercanda atau menjegal kakinya?",
    choices:["Karena baju temanmu akan kotor","Karena orang yang diserang mendadak (tidak siap) tidak bisa menumpukan tangan untuk melindungi diri, dan bisa membenturkan kepalanya keras ke tanah dan mengalami luka yang membahayakan nyawanya","Karena mendorong membuat beratmu sendiri berkurang","Karena seseorang akan memarahimu dan menyuruhmu berdiri di koridor"],
    answerIndex:1,
    explanation:"Seseorang, jika tahu 'mungkin aku akan jatuh', bisa menumpukan tangan tanpa sadar untuk melindungi wajah dan kepalanya. Tetapi jika ia tiba-tiba didorong dari belakang atau dijegal tanpa peringatan, otak tidak punya waktu bersiap melindunginya, sehingga tangannya tidak keluar dan ia menabrak batu atau sudut keras di tanah dengan wajah atau kepalanya lebih dulu. Jika tulang tengkorak patah atau otak terluka parah, itu menjadi kecelakaan mengerikan yang bisa membuatnya tak bisa berjalan seumur hidup, atau merenggut nyawanya. Apa yang kamu kira 'hanya bercanda kecil' bisa merenggut nyawa teman yang kamu sayang. Selalu bertindaklah dengan bayangan untuk tidak pernah melakukan kepada orang lain hal yang benar-benar berbahaya jika dilakukan kepadamu." },
  { id:21, topic:"Kekuatan magnet", emoji:"🧲",
    question:"Ketika kamu mendekatkan dua magnet dan mencoba menyatukan tanda yang sama (U dengan U, atau S dengan S), apa yang terjadi?",
    choices:["Keduanya menempel kuat","Dengan gaya tak terlihat, keduanya saling mendorong kuat dan berusaha menjauh (saling menolak)","Magnetnya tiba-tiba berubah menjadi pasir","Tidak terjadi apa-apa"],
    answerIndex:1,
    explanation:"Magnet punya dua wajah berbeda, disebut 'kutub U' dan 'kutub S'. Ketika kamu mendekatkan wajah yang berbeda (U dan S), keduanya menempel kuat dan akrab. Tetapi ketika kamu mencoba menyatukan wajah yang sama (U dengan U, atau S dengan S), gaya tak terlihat yang sangat kuat mendorong keduanya untuk saling menjauh, seolah berkata 'pergi sana!'. Gaya tak terlihat dan misterius ini disebut 'magnetisme'. Di pabrik, mesin, bahkan di dalam ponsel di seluruh dunia, gaya yang mendorong dan gaya yang menarik ini dimanfaatkan dengan cerdik untuk membangun banyak teknologi yang menggerakkan dan menghentikan benda." },
  { id:22, topic:"Listrik statis", emoji:"💥",
    question:"Pada hari kering, saat menggosok kuat kain kering atau tongkat plastik ke benda lain, muncul listrik misterius yang menarik benda-benda. Apakah itu?",
    choices:["Listrik petir dari stopkontak","'Listrik statis', yang menggeretak dan memercikkan bunga api serta menarik debu ringan dan rambut","Listrik yang mendinginkan air","Tidak terjadi apa-apa"],
    answerIndex:1,
    explanation:"Ketika kamu menggosok kuat dua benda, partikel listrik kecil yang tadinya tersembunyi di dalam berkumpul di permukaan dan mulai mengamuk. Ini disebut 'listrik statis'. Listrik statis punya kekuatan misterius untuk menarik benda ringan di dekatnya — rambut, debu, kertas tipis — dengan 'wuss', persis seperti magnet. Di tempat gelap, kadang terlihat percikan biru kecil menggeretak. Bahkan alat kering yang tampak tidak melakukan apa-apa pun bisa menghasilkan listrik melalui gesekan: sebuah mekanisme alam yang menarik." },
  { id:23, topic:"Bayangan dan matahari", emoji:"🌇",
    question:"Saat kamu berdiri di luar, bayangan yang kamu jatuhkan di tanah paling panjang ketika matahari berada di posisi mana?",
    choices:["Ketika matahari tepat di atas kepalamu, di titik tertinggi","Pada pagi atau sore, ketika matahari rendah, dekat tanah","Ketika matahari tersembunyi di balik awan","Panjangnya selalu sama"],
    answerIndex:1,
    explanation:"Panjang bayangan berubah menurut aturan tetap setiap hari, sesuai 'tinggi' matahari. Pada pagi dan sore, ketika matahari rendah dan dekat tanah, cahaya masuk dari samping dengan sudut panjang dan miring, sehingga bayangan di tanah memanjang sangat jauh. Sebaliknya, sekitar siang, ketika matahari tepat di atas kepalamu di titik tertinggi, cahaya jatuh lurus ke bawah, sehingga bayangan menyusut kecil di kakimu dan menjadi paling pendek. Bahkan tanpa jam atau listrik, dengan mengamati cermat 'arah dan panjang bayangan', kamu bisa memperkirakan dengan tepat kira-kira pukul berapa sekarang dan berapa lama lagi sampai malam tiba." },
  { id:24, topic:"Bagaimana panas merambat", emoji:"🥄",
    question:"Kamu mencelupkan sendok logam dan sendok kayu ke dalam panci sup di atas api. Mana yang lebih cepat menjadi panas berbahaya saat disentuh?",
    choices:["Sendok kayu","Sendok logam (besi atau aluminium)","Keduanya sama sekali tidak panas","Keduanya menjadi sama panas pada saat yang sama"],
    answerIndex:1,
    explanation:"Di antara bahan-bahan di dunia, ada yang 'sangat baik merambatkan panas' dan ada yang 'buruk merambatkannya'. Logam seperti besi dan aluminium punya sifat memindahkan panas di dalamnya dengan kecepatan luar biasa (penghantaran panas), sehingga panas merambat dari dasar panci yang menyentuh api sampai ke bagian atas yang kamu pegang, dan menjadi sangat panas dalam sekejap. Jika kamu menyentuhnya sembarangan, kamu terkena luka bakar parah. Sebaliknya, kayu, kain, dan plastik buruk merambatkan panas, sehingga tidak cepat panas meski dekat api. Saat memakai api untuk memasak dengan aman, kamu butuh kebijaksanaan mengenali sifat bahan ini dan menyisipkan kayu atau kain di tempat yang kamu pegang." },
  { id:25, topic:"Apa itu suara", emoji:"🥁",
    question:"Apa hakikat sejati dari semua 'suara' — suaramu sendiri, suara gendang, gonggongan anjing, dan sebagainya?",
    choices:["Gumpalan udara yang mengeras dan terbang ke arahmu","Gaya benda yang bergetar halus, yang sampai ke telingamu berubah menjadi gelombang di udara","Suara serangga tak terlihat","Cahaya yang berubah menjadi suara"],
    answerIndex:1,
    explanation:"Hakikat sejati semua suara adalah 'getaran'. Ketika kamu memukul gendang, kulitnya bergetar halus, dan ketika kamu menaruh tangan di tenggorokan lalu bersuara, kamu merasakan bagian dalam tenggorokanmu bergetar. Getaran benda ini menggetarkan 'udara' di sekitarnya satu demi satu, dan merambat berubah menjadi gelombang (gelombang suara), menggetarkan selaput di bagian dalam telinga kita, sehingga otak menangkapnya sebagai 'suara'. Di ruang hampa angkasa, yang sama sekali tidak ada udara, sekeras apa pun kamu berteriak atau memukul gendang, tidak ada yang merambatkan getaran, sehingga benar-benar sunyi. Mengetahui bahwa suara adalah getaran adalah dasar dari semua komunikasi dan musik." },
  { id:26, topic:"Pemantulan cahaya", emoji:"🔦",
    question:"Ketika kamu mengarahkan cahaya matahari ke 'cermin' atau permukaan air yang tenang, apa yang terjadi pada cahaya?",
    choices:["Cahaya diserap cermin dan lenyap","Memantul lurus, dengan sudut yang sama seperti sudut datangnya (memantul)","Cahaya bertambah dua kali lebih terang","Warna cahaya menjadi seluruhnya hitam"],
    answerIndex:1,
    explanation:"Ketika cahaya mengenai sesuatu yang halus dan rata, ia punya sifat 'memantul' dengan sudut yang rapi, persis seperti bola yang mengenai dinding. Ini disebut 'pemantulan' cahaya. Jika kamu tahu sifat ini, kamu bisa memakai cermin atau logam yang dipoles mengilap untuk memantulkan cahaya matahari dan menerangi bagian dalam gua gelap yang tak terjangkau cahaya, atau mengirim isyarat cahaya berkelip kepada kawan yang jauh di puncak gunung untuk memperingatkan bahaya atau meminta tolong." },
  { id:27, topic:"Air dan es", emoji:"🧊",
    question:"Jika kamu membiarkan 'air' dalam ember di tempat yang sangat dingin, cukup dingin untuk membekukannya, bagaimana wujudnya berubah?",
    choices:["Berubah menjadi air panas","Berubah menjadi 'es' yang keras dan padat, dan seluruh volumenya bertambah sedikit dan menjadi lebih besar","Airnya berkurang menjadi separuh jumlahnya","Tidak ada yang berubah"],
    answerIndex:1,
    explanation:"Air adalah zat misterius yang sangat berubah wujud menurut suhu: 'cair, padat, gas'. Ketika suhu turun dan membeku, ia berubah menjadi 'es' yang keras. Hampir semua benda menyusut saat didinginkan, tetapi air istimewa: saat menjadi es, susunan di dalamnya berubah, sehingga ia punya sifat langka di mana keseluruhannya 'mengembang sedikit dan menjadi lebih besar (volumenya bertambah)'. Karena itu, jika kamu membekukan botol kaca atau pipa besi yang terisi air penuh sampai ke tepi tanpa celah, ia tak tahan menahan gaya mengembang dari dalam, dan botol atau pipa itu meledak dengan keras dan pecah. Untuk merawat alat di daerah dingin, kebijaksanaan mengetahui perubahan air ini sangatlah penting." },
  { id:28, topic:"Bagaimana benda larut", emoji:"🧂",
    question:"Kamu memasukkan 'garam' atau 'gula' ke dalam air dan mengaduknya rata, lalu wujudnya hilang dari pandangan. Apa yang terjadi pada garam di dalam air ini?",
    choices:["Lenyap sepenuhnya dan tidak ada lagi","Terurai menjadi partikel terlalu kecil untuk dilihat dan 'larut merata (tetap ada)' di seluruh air","Menempel di dasar ember, bersembunyi","Air memakan seluruh garam"],
    answerIndex:1,
    explanation:"Garam atau gula yang bercampur ke air sampai tak terlihat disebut 'pelarutan'. Ia menjadi tak terlihat, tetapi garam itu tidak lenyap ke mana-mana. Ia hanya terpecah menjadi serpihan yang sangat, sangat halus dan tercampur merata di seluruh air. Buktinya, air itu terasa asin, dan jika kamu memanaskan air di atas api lalu menguapkannya sepenuhnya, di dasar tersisa garam semula dengan berat yang persis sama. Walau di masyarakat ada yang mencoba menipumu dengan berkata 'tidak ada di sana karena tak terlihat', dengan mata ilmiah ini kamu bisa melihat hakikat sejati benda dan tidak tertipu." },
  { id:29, topic:"Apa itu angin", emoji:"🌬️",
    question:"'Angin' yang berembus di luar, pada dasarnya, apa yang sedang bergerak?",
    choices:["Napas makhluk raksasa tak terlihat","Aliran 'udara' yang menyelimuti Bumi, yang bergerak saat menghangat dan mendingin","Bayangan yang dijatuhkan oleh cahaya matahari yang berlari","Gaya awan yang menekan tanah"],
    answerIndex:1,
    explanation:"Hakikat sejati angin adalah 'aliran udara' di sekitar kita. Udara di Bumi, saat dihangatkan matahari, menjadi ringan dan naik, dan udara dingin menjadi berat dan turun. Karena perbedaan suhu udara ini, seluruh udara Bumi bergerak dinamis berputar-putar, dan begitulah angin lahir. Angin tidak terlihat, tetapi ditangkap layar ia bisa menggerakkan kapal raksasa, dan dengan memutar baling-baling kincir angin ia bisa menggiling gandum yang berat menjadi tepung atau menghasilkan listrik: itulah 'energi gerak' yang besar dari alam raya." },
  { id:30, topic:"Gravitasi", emoji:"🌍",
    question:"Ketika kamu melepaskan di udara batu yang kamu pegang, batu itu selalu jatuh ke arah 'tanah (bawah)'. Mengapa?",
    choices:["Karena batu itu ingin beristirahat di tanah","Karena 'Bumi' tempat kita tinggal punya gaya bernama 'gravitasi' yang menarik kuat segala benda ke pusatnya","Karena dari atas berembus angin kencang yang mendorongnya","Karena batu itu berat sehingga bergerak sendiri"],
    answerIndex:1,
    explanation:"Segala sesuatu di Bumi, ketika dilepaskan, selalu jatuh ke bawah (ke arah tanah). Ini karena bintang raksasa tempat kita berdiri — Bumi itu sendiri — punya gaya seperti magnet yang menarik semua benda kuat-kuat ke pusatnya. Gaya ini disebut 'gravitasi', atau 'gaya tarik semesta'. Berkat gravitasi ini, secepat apa pun Bumi berputar di angkasa, kita manusia, air laut, dan bangunan tidak terlempar ke angkasa, dan kita bisa hidup dengan aman dengan kaki menapak kuat di tanah." },
  { id:31, topic:"Gaya gesek", emoji:"👟",
    question:"Mengapa di jalan berlumpur atau di atas es itu licin dan mudah jatuh, tetapi di atas batu yang kasar sulit tergelincir?",
    choices:["Karena batu lebih baik hati","Karena 'gaya gesek' yang mengerem saat benda saling bergesekan lebih kuat di permukaan yang kasar","Karena es itu ringan sehingga memantulkan orang","Karena sepatu takut pada es"],
    answerIndex:1,
    explanation:"Ketika benda bersentuhan dan bergerak satu sama lain, selalu ada gaya pengereman bernama 'gesekan' yang berusaha menghentikan gerakan. Di atas es yang licin atau lumpur yang basah, rem gesekan ini hampir tidak bekerja, sehingga kakimu tergelincir dan kamu jatuh keras, dan mudah patah tulang atau terluka. Sebaliknya, di tanah yang kasar, atau di alur dalam pada sol sepatu, gesekan kuat dan mencengkeram tanah erat, sehingga kamu bisa berjalan tanpa tergelincir. Saat berjalan di tempat berbahaya, kebijaksanaan untuk keselamatanmu adalah memperhatikan seberapa aus sol sepatumu dan gesekan tanah." },
  { id:32, topic:"Gaya apung", emoji:"🛶",
    question:"Jika kamu melempar 'batang kayu' yang sangat besar dan berat ke sungai atau laut, apakah tenggelam? Atau mengapung?",
    choices:["Karena berat, ia tenggelam ke dasar dalam sekejap","Meski batang itu sangat besar, ia lebih ringan daripada air dengan ukuran yang sama, sehingga mengapung di air","Hancur berkeping-keping pada saat menyentuh air","Tenggelam atau mengapung berubah tergantung hari"],
    answerIndex:1,
    explanation:"Apakah sesuatu mengapung atau tenggelam di air tidak ditentukan hanya oleh berat totalnya. Itu ditentukan oleh 'apakah ia lebih berat atau lebih ringan (kerapatannya) dibandingkan air dengan ukuran (volume) yang sama'. Kayu punya banyak kantong udara tak terlihat di dalamnya, sehingga sebesar dan seberat apa pun sebuah batang, ia lebih ringan daripada gumpalan air seukuran itu. Karena itu ia menerima gaya yang mendorongnya ke atas dari air (gaya apung) dan terapung naik. Justru karena orang mengetahui aturan alam ini, umat manusia bisa membangun kapal dari potongan kayu besar dan menciptakan teknologi untuk menyeberangi laut sambil mengangkut banyak muatan berat." },
  { id:33, topic:"Cahaya bergerak lurus", emoji:"💡",
    question:"Cahaya matahari atau cahaya senter, bagaimana ia bergerak melalui udara?",
    choices:["Bergerak berkelok-kelok dan membelok, seperti angin","Bergerak 'lurus sempurna (garis lurus)', dan ketika ada sesuatu di jalannya, ia terhalang dan membentuk bayangan di belakang","Bergerak menggambar lingkaran berulang-ulang","Arah geraknya sama sekali tidak tentu"],
    answerIndex:1,
    explanation:"Cahaya punya aturan mutlak: bergerak 'lurus sempurna, sejauh ia pergi', melalui udara. Ini disebut 'perambatan lurus' cahaya. Karena cahaya tidak bisa membelok, ketika sesuatu yang 'tidak meneruskan cahaya' — tubuh manusia, batu besar — berdiri menghalangi jalannya yang lurus, cahaya tidak bisa berputar ke bagian belakang benda itu, dan tersisalah di tanah area gelap yang tak terjangkau cahaya. Inilah hakikat sejati 'bayangan'. Memanfaatkan sifat cahaya yang bergerak lurus, orang membangun gedung dengan lurus sempurna dan mengukur jarak jauh dengan tepat." },
  { id:34, topic:"Udara hangat", emoji:"🔥",
    question:"Saat kamu membuat api unggun, mengapa 'asap' dan udara panas yang keluar selalu naik ke atas (ke langit)?",
    choices:["Karena asap ingin menemui awan di langit","Karena udara 'menjadi ringan saat dihangatkan' dan punya sifat naik semakin tinggi, di atas udara dingin di sekitarnya","Karena dari atas ada benang tak terlihat yang menarik","Karena api melemparkan asap ke atas"],
    answerIndex:1,
    explanation:"Udara punya aturan menarik: beratnya berubah menurut suhu. Udara yang 'dihangatkan' membara oleh panas api menjadi bersemangat dan mengembang besar, menjadi 'lebih ringan beratnya' daripada udara dingin di sekitarnya. Karena itu, seperti balon yang mengapung di air, ia naik dengan sendirinya semakin tinggi. Asap api unggun selalu naik karena menumpang aliran udara hangat ini. Mengetahui gerakan udara ini — 'udara hangat naik, udara dingin turun' (konveksi) — menjadi kebijaksanaan penting untuk mengganti udara di kamar, dan untuk menghindari asap serta melarikan diri dengan aman saat kebakaran." },
  { id:35, topic:"Kembali ke bentuk semula", emoji:"🏹",
    question:"Setelah kamu menarik atau menekuk kuat dengan tangan sebuah karet gelang atau ranting yang lentur, apa yang terjadi saat kamu melepaskannya?",
    choices:["Tetap dalam bentuk tertekuk dan tidak pernah kembali ke bentuk semula","Bekerja dengan kuat sebuah 'gaya yang berusaha kembali ke bentuk semula (elastisitas)'","Berat benda bertambah dua kali lipat","Mengeluarkan panas dan mulai terbakar"],
    answerIndex:1,
    explanation:"Karet dan ranting muda pepohonan punya gaya kuat yang berusaha 'kembali ke bentuk semula dalam sekejap' saat kamu melepaskannya, bahkan setelah bentuknya diubah oleh gaya dari luar. Gaya ini disebut 'elastisitas' dalam bahasa ilmu pengetahuan. Sejak dahulu kala, umat manusia memanfaatkan dengan cerdik gaya kuat yang berusaha kembali ke bentuk semula ini: untuk membuat alat yang melontarkan benda jauh (seperti busur dan panah), untuk membuat jebakan, dan untuk mengikat muatan dengan erat memakai tali yang kuat. Mengetahui gaya pantul benda di sekitarmu menjadi kebijaksanaan untuk menggunakan alat dengan aman." },
  { id:36, topic:"Penguapan", emoji:"🌫️",
    question:"Sebuah 'genangan air' yang terbentuk di tanah setelah hujan lenyap sepenuhnya keesokan harinya saat cerah. Ke mana perginya air itu?",
    choices:["Orang bawah tanah di dasar bumi meminumnya habis","Oleh panas matahari dan sebab lain, ia berubah menjadi partikel kecil tak terlihat (uap air) dan 'bersembunyi ke dalam udara' (menguap)","Air itu ketakutan lalu lari ke suatu tempat","Matahari menyedot air itu dan memakannya"],
    answerIndex:1,
    explanation:"Air genangan lenyap karena air berubah menjadi partikel kecil tak terlihat (uap air dalam wujud gas), bercampur ke udara, dan terbang pergi. Ini disebut 'penguapan' air. Baju basah yang dijemur di luar bisa kering dengan baik juga berkat mekanisme penguapan ini. Air, meski tak lagi terlihat, selalu ada di udara, dan ketika berkumpul tinggi di langit lalu didinginkan, ia kembali menjadi 'awan' dan 'hujan' dan turun lagi ke tanah. Seluruh air di dunia berkelana begini berputar-putar mengelilingi Bumi, sambil berubah wujud (siklus air)." },
  { id:37, topic:"Besi dan karat", emoji:"🔧",
    question:"Jika kamu membiarkan pisau atau alat besi berharga tergeletak di atas lumpur dalam keadaan masih basah, apa yang terjadi?",
    choices:["Besinya terpoles dan mulai berkilau","Oksigen di udara dan air bersatu dengan besi, mengubahnya menjadi 'karat' cokelat kemerahan yang rapuh, dan alatnya rusak","Besinya tumbuh semakin besar dan menjadi besar serta berat","Tidak ada yang berubah"],
    answerIndex:1,
    explanation:"Besi adalah logam yang sangat kokoh dan berguna, tetapi punya kelemahan besar. Jika kamu membiarkannya basah, atau membiarkannya terpapar udara dalam waktu lama, ia bereaksi kimia dengan air dan oksigen dan berubah menjadi zat cokelat kemerahan yang rapuh. Ini disebut 'karat' (pengaratan) besi. Besi yang berkarat kehilangan kekuatannya dan rontok hanya dengan disentuh, menjadi tak berguna sebagai alat. Untuk melindungi alat berharga dari karat, kamu butuh kebijaksanaan perawatan harian: setelah memakainya, selalu lap airnya hingga bersih dan oleskan lapisan tipis 'minyak' di permukaan, agar air dan udara tidak menyentuh besi secara langsung." },
  { id:38, topic:"Fotosintesis", emoji:"🌱",
    question:"Meski kamu memberi banyak air setiap hari pada tanaman di kebun atau ladang, apa yang terjadi jika kamu mengurungnya dalam 'kotak yang sangat gelap' yang sama sekali tak terjangkau cahaya?",
    choices:["Tumbuh bebas dan besar karena tidak terkena matahari","Tanpa cahaya ia tidak bisa membuat sendiri makanan (energi) untuk hidup, sehingga menguning dan layu","Tanaman berubah menjadi hewan dan pergi berjalan","Tidak ada yang berubah"],
    answerIndex:1,
    explanation:"Manusia dan hewan memperoleh energi untuk hidup dengan memakan makanan lain melalui mulut. Tetapi tanaman, yang tak bisa berpindah dari tanah, harus membuat energinya sendiri dengan kekuatannya sendiri. Dengan memandikan daun hijaunya dalam 'cahaya matahari', tanaman punya kekuatan ajaib untuk membuat, dari air dan udara, makanan terbaik (gula seperti pati) untuk membangun tubuhnya sendiri. Ini disebut 'fotosintesis'. Sebanyak apa pun kamu menyiramnya, di tempat yang sangat gelap tanpa cahaya matahari, tanaman mengalami kekurangan gizi dan layu 100%. Inilah dasar untuk memahami betapa pentingnya cahaya matahari dalam pertanian." },
  { id:39, topic:"Air selalu rata", emoji:"🥛",
    question:"Saat kamu menuang air ke dalam cangkir atau piring, sememiringkan apa pun kamu memiringkan wadahnya, apa yang terjadi pada bentuk permukaan air?",
    choices:["Membeku dalam keadaan miring dengan sudut yang sama dengan wadahnya","Sememiringkan apa pun wadahnya, permukaan air selalu menjadi 'rata (datar) dengan tanah Bumi'","Permukaan air meruncing ke atas seperti segitiga","Mulai berputar-putar mengikuti kemiringan wadah"],
    answerIndex:1,
    explanation:"Zat cair seperti air selalu ditarik lurus ke bawah oleh gravitasi Bumi, sehingga di wadah mana pun kamu menaruhnya dan memiringkannya, permukaannya selalu menjadi 'keadaan yang benar-benar rata', sejajar dengan tanah. Ini disebut 'datar' (rata). Dahulu kala, tukang kayu dan para pembangun sangat memanfaatkan sifat air ini. Dengan mengisi air ke pipa atau parit bening, mereka membuat alat (waterpas) untuk memeriksa dengan ketepatan 100% apakah lantai dan tiang bangunan yang sedang mereka buat 'benar-benar rata terhadap tanah' atau 'miring dan bengkok'. Air adalah guru yang mengajari kita 'kedataran' dunia." },
  { id:40, topic:"Membawa muatan berat", emoji:"📦",
    question:"Saat kamu membawa dengan tangan seikat kayu bakar atau muatan yang sangat berat, cara memegang mana yang membuatmu bisa membawanya dengan stabil dan aman memakai 'tenaga paling ringan'?",
    choices:["Merentangkan lengan lurus dan panjang ke depan dan memegangnya jauh dari tubuh","Memegang muatan menempel erat ke perut atau dada, menopangnya di pusat tubuhmu","Menyeimbangkannya pas-pasan di atas kepala dan memegang dengan satu tangan","Memegang muatan tergantung hanya di ujung jari"],
    answerIndex:1,
    explanation:"Saat membawa sesuatu yang berat, memegangnya jauh dari tubuh bekerja seperti tuas: berat muatan menimpa lengan dan pinggangmu berlipat-lipat, sehingga kamu cepat kehabisan tenaga atau kehilangan keseimbangan dan terbalik. Tetapi ketika kamu menarik muatan menempel erat ke 'daerah perut atau dada (pusat tubuhmu, pusat gravitasimu)' dan memegangnya dekat, berat muatan menyatu dengan beratmu sendiri, sehingga kamu bisa membawanya dengan goyangan paling sedikit dan tenaga yang sangat ringan, dengan aman. Inilah kebijaksanaan bersama seluruh dunia tentang cara menggunakan tubuh, untuk memakai tenagamu yang sedikit dengan hati-hati dan bekerja dengan efisien tanpa terluka." },
  { id:41, topic:"Gempa: di dalam", emoji:"🏠",
    question:"Tanah mulai berguncang keras (gempa bumi). Saat kamu berada di dalam gedung, apa hal pertama yang harus dilakukan?",
    choices:["Buru-buru lari ke luar dalam kepanikan","Merangkak ke bawah meja atau meja yang kokoh, dan lindungi kepalamu baik-baik di tempat yang perabotnya tidak akan menimpamu","Mendekat ke jendela dan melihat keadaan di luar","Berlari-lari di dalam ruangan sambil berteriak keras"],
    answerIndex:1,
    explanation:"Saat gempa terjadi, yang paling berbahaya adalah 'benda jatuh dari atas' dan 'perabot berat terguling lalu menindihmu di bawahnya'. Kalau kamu mencoba lari ke luar dalam kepanikan, kaca pecah atau genteng bisa jatuh ke kepalamu dan melukaimu parah. Saat merasakan guncangan, pertama bersembunyilah di bawah sesuatu yang kokoh yang menahan benturan dari atas, seperti meja atau ranjang. Lalu jaga kepalamu tertutup dengan tangan atau bantal dan tunggu diam sampai guncangan berhenti sepenuhnya: ini adalah aturan pertama untuk melindungi nyawa, yang sama di seluruh dunia." },
  { id:42, topic:"Gempa: di luar", emoji:"🏞️",
    question:"Guncangan besar (gempa bumi) terjadi saat kamu berjalan di luar. Ke mana paling aman untuk melarikan diri?",
    choices:["Ke dekat gedung tinggi, tembok bata tua, atau tebing","Tempat yang banyak papan reklame dan pohon","Tempat terbuka, luas, dan aman yang tidak ada apa pun di sekitarnya yang bisa menimpamu","Di bawah jembatan besar di dekatnya"],
    answerIndex:2,
    explanation:"Kalau gempa terjadi saat kamu di luar, aturan mutlaknya adalah 'menjauh sejauh mungkin' dari gedung dan tembok. Tembok bata atau beton tua, kaca gedung, dan tebing bisa runtuh dalam sekejap akibat guncangan dan menjadi senjata berbahaya yang menimpa orang. Pindahlah ke tempat luas dan terbuka yang tidak ada gedung yang bisa roboh, tidak ada papan reklame yang jatuh, dan tidak ada lereng yang longsor. Kalau tidak ada tempat seperti itu di dekatmu, lindungi kepalamu erat-erat dengan tas atau sejenisnya, dan tunggu guncangan berhenti di jalan yang aman, jauh dari gedung." },
  { id:43, topic:"Air banjir", emoji:"🌧️",
    question:"Hujan deras turun dan air membanjiri jalan. Kalau arusnya kira-kira sedalam lutut, apakah boleh menyeberang dengan berjalan kaki?",
    choices:["Sedalam lutut itu dangkal, jadi kamu bisa menyeberang sambil berlari dengan mudah","Jangan pernah menyeberang. Kekuatan air yang mengalir sangat besar, dan bahkan sedalam lutut pun bisa dengan mudah menghanyutkan orang dewasa","Aman kalau menyeberang sambil berenang","Boleh menyeberang kalau airnya bersih"],
    answerIndex:1,
    explanation:"Jangan meremehkan kekuatan air yang mengalir. Saat air mencapai setinggi lutut, arus mendorong kuat untuk menghanyutkan kakimu, sehingga bahkan orang dewasa pun tak bisa berdiri tegak: ia jatuh dalam sekejap dan terhanyut ke air dalam di hilir. Selain itu, kita tak bisa melihat menembus air keruh, sehingga di seluruh dunia terjadi kecelakaan mengerikan di mana orang jatuh ke parit dalam yang tersembunyi atau lubang got terbuka lalu tenggelam. Begitu air mulai mengalir di jalan, jangan pernah memaksakan diri lewat dengan berjalan: penting untuk segera mengungsi ke tempat tinggi yang tak terjangkau air." },
  { id:44, topic:"Banjir bandang", emoji:"⛈️",
    question:"Di tempatmu cerah, tetapi jauh di pegunungan kamu melihat awan hitam dan mendengar gemuruh. Saat kamu berada di dekat sungai, apa yang kamu lakukan?",
    choices:["Di atasmu cerah, jadi kamu terus bermain di sungai seperti biasa","Hujan deras sedang turun di hulu (di pegunungan), dan sekarang bisa tiba-tiba menerjang air yang mengerikan (banjir bandang), jadi segera menjauh dari sungai dan larilah ke tempat tinggi","Menunggu dengan tenang sampai air sungai menjadi keruh","Masuk ke sungai untuk menyejukkan badan"],
    answerIndex:1,
    explanation:"Yang menakutkan dari sungai adalah, meski di tempatmu cerah, ketika hujan deras turun di 'hulu, di pegunungan' tempat sungai bermula, air dalam jumlah besar yang terkumpul di sana menjadi gumpalan berkecepatan tinggi seperti tsunami dan menerjang ke hilir dalam sekejap. Ini disebut 'banjir bandang'. Kalau kamu melihat awan hitam di pegunungan, mendengar suara petir, melihat air sungai tiba-tiba keruh, atau melihat makin banyak ranting hanyut, itu adalah tanda alam bahwa banjir besar sedang mendekat. Keluarlah dari sungai dan pindah ke tempat tinggi walau satu detik lebih cepat." },
  { id:45, topic:"Petir dan pohon", emoji:"🌩️",
    question:"Ada kilat dan petir menyambar hebat. Saat kamu di luar, apakah aman berteduh dari hujan 'tepat di bawah pohon tinggi'?",
    choices:["Di bawah pohon seperti atap, jadi itu tempat paling aman di dunia","Sangat berbahaya. Petir mudah menyambar benda tinggi, dan listrik yang menyambar pohon melompat ke orang yang berada tepat di bawahnya (sambaran samping)","Kalau memanjat pohon, petir tidak akan mengenaimu","Mengangkat payung tinggi-tinggi dan berdiri di bawah pohon"],
    answerIndex:1,
    explanation:"Saat petir menyambar, berteduh di bawah pohon tinggi adalah hal yang sama sekali tidak boleh kamu lakukan. Petir punya sifat menyambar 'benda yang paling tinggi dan runcing' di suatu area. Karena itu peluang petir menyambar pohon sangat tinggi, dan listrik dahsyat yang menyambar pohon mengalir lebih mudah lewat tubuh orang yang berada sangat dekat daripada lewat pohon, sehingga listrik 'melompat ke samping' dari pohon ke orang itu. Ini disebut 'sambaran samping'. Kamu harus selalu menjaga jarak setidaknya 4 meter dari pohon." },
  { id:46, topic:"Aman dari petir", emoji:"🚗",
    question:"Saat petir menggelegar hebat di mana-mana, di mana tempat paling aman untuk melindungi diri?",
    choices:["Berdiri di tengah lapangan datar dan terbuka","Di dalam gedung kokoh dari beton atau bata, atau di dalam mobil yang seluruhnya terbungkus logam","Di dalam tenda besar","Di dalam air kolam atau sungai"],
    answerIndex:1,
    explanation:"Yang paling aman untuk melindungi diri dari petir adalah masuk ke dalam gedung yang kokoh. Listrik lolos ke tanah lewat dinding dan tiang, jadi tidak sampai ke orang di dalam. Mobil atau bus yang seluruhnya terbungkus logam (besi) juga sangat aman. Meski petir menyambar mobil, listrik mengalir rapi lewat bodi luar dan lolos dari ban ke tanah, sehingga orang yang duduk di dalam tidak terluka. Sebaliknya, berdiri sendirian di tengah lapangan terbuka sangat berbahaya, karena kamu sendiri menjadi 'benda runcing tertinggi' dan memanggil petir." },
  { id:47, topic:"Asap kebakaran dan sikap tubuh", emoji:"🚪",
    question:"Kebakaran terjadi di dalam gedung. Saat ruangan dipenuhi asap, bagaimana kamu harus melarikan diri?",
    choices:["Berlari dengan dada tegak dan sikap tinggi supaya bisa melihat asap dengan jelas","Asap lebih ringan daripada udara dan 'berkumpul di atas', jadi untuk menghirup udara bersih dekat lantai, melarikan dirilah dengan sikap rendah, merangkak di lantai","Berjongkok di sudut ruangan dan menunggu asap hilang","Menarik napas besar ke arah langit-langit"],
    answerIndex:1,
    explanation:"Seperti yang kamu pelajari di paket mekanika sebelumnya, udara panas dan asap punya sifat mutlak 'lebih ringan daripada udara dingin, jadi naik makin tinggi'. Karena itu, di dalam ruangan yang terbakar, asap mengerikan dan gas berbahaya menumpuk dari langit-langit ke bawah. Sebaliknya, dekat lantai (sekitar 30 sentimeter dari lantai) sampai akhir tersisa udara bersih yang masih bisa kamu hirup. Saat melarikan diri menembus asap, jaga 'sikap rendah', membungkukkan punggung dan merangkak di lantai sambil menuju pintu keluar: ini adalah kode bertahan hidup yang sama di seluruh dunia." },
  { id:48, topic:"Jangan menghirup asap", emoji:"😷",
    question:"Saat melarikan diri menembus asap kebakaran, apa yang baik dilakukan agar tidak menghirup asap?",
    choices:["Menekankan handuk kering ke mulut","Menutup rapat mulut dan hidung dengan kain atau pakaian yang dibasahi air, dan melarikan diri sambil bernapas pelan dan pendek","Bernapas sambil berteriak keras","Tidak melakukan apa-apa dan langsung berlari saja"],
    answerIndex:1,
    explanation:"Sebagian besar kematian dalam kebakaran bukan karena terbakar api, melainkan karena menghirup gas berbahaya dalam asap, seperti 'karbon monoksida', lalu kehilangan kesadaran. Agar tidak menghirup asap, efektif menekankan kuat sapu tangan atau pakaian yang dibasahi air ke mulut dan hidung. Celah-celah halus pada kain basah berperan sebagai 'penyaring' yang menangkap jelaga berbahaya dan percikan api dalam asap. Dan alih-alih berlari sambil menarik napas besar terengah-engah, bernapaslah pelan dan pendek lewat sapu tangan sambil dengan tenang menuju pintu keluar." },
  { id:49, topic:"Tanah longsor", emoji:"⛰️",
    question:"Setelah hujan deras turun berhari-hari, mengapa berbahaya berjalan di dekat gunung atau di bawah tebing?",
    choices:["Karena gunung menjadi dingin dan kamu masuk angin","Karena tanah menyerap air dalam jumlah besar dan menjadi seperti lumpur, dan lereng gunung bisa runtuh dalam sekejap (tanah longsor)","Karena hewan-hewan gunung marah lalu turun","Karena tanah mengering dan mengeras"],
    answerIndex:1,
    explanation:"Tanah dan batu tetap padat saat ada kelembapan yang pas, tetapi ketika hujan deras turun berhari-hari, terlalu banyak air terkumpul di celah-celah tanah dan tanah menjadi seperti sup encer. Tanah yang sudah berat tidak kuat menahan gravitasi dan, dalam sekejap, tanpa peringatan, seluruh lereng runtuh dengan kecepatan dahsyat. Ini disebut 'tanah longsor'. Jangan pernah mendekati gunung atau tebing saat hujan atau tepat setelah hujan berhenti. Kalau air keruh menyembur dari tanah, atau kamu mendengar batu berguguran, itu adalah tanda berbahaya bahwa gunung sebentar lagi longsor." },
  { id:50, topic:"Tsunami", emoji:"🌊",
    question:"Saat kamu di dekat laut, tanah berguncang keras dengan hentakan (gempa bumi). Apa hal terpenting yang harus dilakukan segera sesudahnya?",
    choices:["Air laut mungkin surut dan kamu bisa menangkap ikan, jadi mendekat ke pantai","Dinding air raksasa (tsunami) bisa datang dari laut lepas dengan kecepatan dahsyat, jadi menjauhlah dari laut walau satu detik lebih cepat dan larilah ke 'gunung tinggi atau dataran tinggi yang kokoh'","Menggali lubang di pantai berpasir dan bersembunyi","Naik perahu dan berangkat ke laut lepas"],
    answerIndex:1,
    explanation:"Saat gempa besar terjadi di bawah laut, dasar laut bergerak hebat, sehingga seluruh massa air laut di atasnya menjadi gelombang raksasa yang menerjang ke pantai. Inilah 'tsunami'. Tsunami sama sekali berbeda dari ombak biasa: ia adalah 'dinding air raksasa' yang menyatu dari dasar laut sampai permukaan. Kekuatannya cukup dahsyat untuk merobohkan rumah dan pohon dalam sekejap. Sebelum tsunami datang, air laut di pantai kadang surut tajam dengan desiran aneh, tetapi kalau kamu merasa itu menarik dan mendekat, kamu sama sekali tidak akan selamat. Kalau merasakan guncangan di tepi laut, jangan membawa apa pun dan langsung berlari ke tempat tinggi sekarang juga." },
  { id:51, topic:"Tornado dan angin kencang", emoji:"🌪️",
    question:"Angin kencang yang luar biasa, atau angin hebat yang berpusar (tornado), mendekat ke arahmu. Di mana paling aman untuk berlindung?",
    choices:["Berpegangan pada cabang pohon besar di luar","Masuk ke gedung kokoh dari beton atau sejenisnya yang tidak ada kaca jendela, meringkuk di sudut dinding, dan lindungi kepala","Membuka payung di luar dan menahan angin","Memanjat ke atap datar"],
    answerIndex:1,
    explanation:"Teror sejati dari angin kencang hebat atau tornado bukan hanya kekuatan angin itu sendiri, melainkan bahwa benda-benda yang diterbangkan angin — 'papan reklame, genteng, ranting, batu' — terbang ke arahmu dengan kecepatan dahsyat seperti peluru. Kalau mengenai tubuhmu, mereka melukaimu parah. Selain itu, kalau kaca jendela gedung pecah karena tekanan angin, pecahannya berhamburan ke dalam ruangan dan sangat berbahaya. Saat angin kencang datang, segera masuk ke gedung kokoh dan berjongkoklah 'di tengah ruangan yang paling jauh dari jendela, atau di sudut dinding'. Lalu peganglah kepalamu dengan kedua tangan dan meringkuklah mengecilkan tubuh untuk melindungi diri." },
  { id:52, topic:"Badai pasir dan abu", emoji:"🌋",
    question:"Saat 'badai pasir' hebat yang menggelapkan langit, atau 'abu vulkanik' dari gunung berapi, turun, apa yang harus kamu lindungi?",
    choices:["Melindungi telapak kaki agar sepatu tidak kotor","Agar tidak menghirup pasir atau abu halus lalu merusak paru-paru, atau masuk ke mata dan melukainya, tutup rapat wajahmu (mulut, hidung, mata) dengan kain basah","Melindungi uang di saku","Menyanyi keras-keras untuk meniup abu menjauh"],
    answerIndex:1,
    explanation:"Pasir badai pasir dan abu yang turun dari gunung berapi itu seperti 'pecahan kaca kecil atau butiran batu', sangat halus dan runcing. Kalau kamu menghirupnya langsung lewat mulut atau hidung, bagian dalam paru-paru terluka dan kamu tak bisa bernapas, sehingga menimbulkan penyakit berat. Dan kalau masuk ke mata, rasa sakit yang kuat membuatmu tak bisa membukanya. Saat badai pasir atau abu turun, tutup rapat mulut dan hidungmu dengan kain atau pakaian lembap, dan lindungi mata lewat kain atau tutup sepenuhnya, membuat penghalang agar butiran halus tidak masuk ke tubuhmu. Lalu bertahanlah diam di tempat aman di dalam ruangan atau di balik sesuatu sampai butirannya berlalu." },
  { id:53, topic:"Jarak pandang nol", emoji:"🌨️",
    question:"Saat berjalan di luar, tiba-tiba muncul 'kabut' tebal atau 'badai salju' hebat, dan sekelilingmu menjadi putih sehingga kamu tak bisa melihat apa-apa. Apa yang kamu lakukan?",
    choices:["Percaya pada nalurimu dan, apa pun yang terjadi, terus berlari maju","Bergerak memaksakan diri bisa membuatmu jatuh dari tebing atau tersesat, jadi berlindunglah di balik batu yang aman atau sejenisnya dan tunggu diam tanpa bergerak sampai pandangan jernih","Berlari berputar-putar sambil berteriak keras","Berbaring di tanah lalu tidur"],
    answerIndex:1,
    explanation:"'Jarak pandang nol', saat kamu tak bisa lagi melihat pemandangan di sekitarmu di alam bebas, adalah jebakan mengerikan yang bisa merenggut nyawa bahkan orang dewasa. Kalau dalam kabut atau badai salju kamu mulai berjalan mengandalkan naluri, berpikir 'lewat sini', kamu kehilangan arah hadapmu, tak bisa kembali ke titik awal, atau jatuh terjungkal dari tepi tebing tanpa menyadarinya. Saat kamu mencapai keadaan tak bisa melihat satu langkah di depan, yang benar adalah, pertama-tama, jangan memaksakan satu langkah pun. Berlindunglah di balik batu aman yang menahan angin dan dingin, dan tunggu dengan sabar sampai kabut menipis atau badai salju berhenti." },
  { id:54, topic:"Gerhana dan mata", emoji:"👁️",
    question:"Saat pertunjukan langit yang langka seperti 'gerhana matahari', di mana bentuk matahari berubah, apakah boleh menatap matahari langsung dengan matamu sendiri?",
    choices:["Karena peristiwa langka, kamu harus membuka mata lebar-lebar dan menatapnya baik-baik","Sama sekali tidak boleh. Cahaya matahari sangat kuat, dan menatapnya langsung membakar sel-sel penting di dalam mata, dengan risiko kamu tak bisa melihat lagi selamanya (kebutaan)","Kalau memakai kacamata hitam, aman ditatap berjam-jam pun","Boleh menatap langsung matahari yang terpantul di genangan air"],
    answerIndex:1,
    explanation:"Matahari memancarkan cahaya indah yang menghidupi semua kehidupan di Bumi, tetapi energi cahaya itu 'cukup kuat untuk menghancurkan mata manusia dalam sekejap'. Meski saat gerhana matahari tampak sedikit tertutup dan lebih gelap, kekuatan cahaya yang keluar tidak berubah. Kalau kamu menatap matahari langsung dengan mata telanjang, sel terpenting di mata yang mengatur fokus (retina) hangus terbakar, sama seperti kaca pembesar membakar kertas. Sel yang hangus tak pernah kembali normal, dan kamu bisa kehilangan penglihatan seumur hidup. Saat menatap matahari, selalu patuhi aturan memakai alat khusus yang aman." },
  { id:55, topic:"Pasir isap", emoji:"🆘",
    question:"Saat berjalan, tanah di bawah kakimu menjadi seperti lumpur dan tubuhmu mulai tenggelam makin dalam (pasir isap). Bagaimana kamu bergerak?",
    choices:["Mencoba menarik kaki dengan menggelepar dan menggerakkan kaki dengan keras","Makin menggelepar makin tenggelam, jadi jangan panik: rebahkan tubuhmu ke belakang untuk memperluas 'luas permukaan', menghadap ke atas, dan mengapung sambil menunggu bantuan","Menggali banyak lumpur dengan tangan","Mengikatkan pemberat ke tubuh"],
    answerIndex:1,
    explanation:"Saat terjebak di pasir isap atau lumpur dalam, yang paling tidak boleh dilakukan adalah 'menggelepar dengan keras'. Kalau kamu mencoba menarik satu kaki kuat-kuat ke atas, sebanyak itu pula 'seluruh berat badan (kekuatan besar) terpusat pada kaki yang satunya', sehingga tubuhmu tenggelam makin dalam. Kalau terjebak, pertama hentikan gerakan dan rebahkan tubuh bagian atas ke belakang di atas lumpur, terbentang seperti bintang. Seperti yang kamu pelajari di paket mekanika sebelumnya, dengan menyebarkan beratmu ke area yang luas, kamu lebih sulit tenggelam ke dalam lumpur dan bisa mengapung. Dalam posisi itu, panggil bantuan dengan tenang." },
  { id:56, topic:"Hewan liar", emoji:"🐾",
    question:"Saat berjalan di luar, di depanmu muncul 'anjing liar atau hewan buas' menyeramkan yang memamerkan taring. Bagaimana kamu menjauh?",
    choices:["Membalikkan badan dan lari secepat tenaga sambil berteriak keras","Jangan pernah lari. Hewan punya naluri mengejar yang berlari, menganggapnya 'mangsa', jadi jangan beradu pandang dan mundurlah pelan-pelan untuk menjauh","Menatap tajam matanya dan menantangnya berkelahi","Berbaring di tanah dan berpura-pura mati"],
    answerIndex:1,
    explanation:"Karnivora liar dan anjing yang kelaparan jauh lebih cepat daripada manusia. Saat hewan muncul di depanmu, kalau dalam panik ketakutan kamu membalikkan badan dan 'lari secepat tenaga', sebuah sakelar liar di otak hewan — 'mengejar dan menghabisi mangsa yang lari' — menyala, dan ia menyerang dengan kecepatan dahsyat. Kalau kamu berjumpa hewan liar, pertama tenangkan hatimu tanpa berteriak, palingkan sedikit pandangan agar tidak memancingnya, dan tanpa menunjukkan punggung, 'mundur pelan-pelan dan sangat perlahan, satu langkah demi satu langkah' untuk memberi jarak. Mengetahui naluri hewan adalah kebijaksanaan pertahanan." },
  { id:57, topic:"Sarang lebah", emoji:"🐝",
    question:"Di hutan kamu menemukan 'sarang lebah' besar di pohon. Di sekitarnya lebah berterbangan. Apa yang harus kamu lakukan?",
    choices:["Karena langka, kamu melempar batu untuk menjatuhkan sarangnya","Jangan pernah mendekat. Kalau kamu berteriak atau menggelepar, lebah mengira 'sarang diserang' dan menyerbu berbondong-bondong ke arahmu, jadi tinggalkan tempat itu dengan tenang dalam sikap rendah","Mengibaskan tangan keras-keras untuk berteman dengan lebah","Berdiri tepat di bawah sarang dan mengamatinya"],
    answerIndex:1,
    explanation:"Serangga seperti lebah biasanya tidak menyerang manusia tanpa alasan. Tetapi ketika manusia mendekati 'sarang' mereka, yang merupakan anak-anak dan rumah mereka, mereka masuk ke mode waspada yang kuat. Kalau lalu manusia berteriak, mengibas-ngibaskan tangan dengan keras, atau melempar batu, lebah memutuskan 'musuh datang menghancurkan sarang!' dan mengirim sinyal racun khusus ke semua kawan, lalu ratusan dari mereka menyerbu menyengat sekaligus. Disengat racun lebah berkali-kali bisa merenggut nyawamu. Kalau menemukan sarang, tahan napas dengan tenang, rendahkan sikap tubuh, dan menyingkirlah dari tempat itu perlahan." },
  { id:58, topic:"Air setelah bencana", emoji:"🚰",
    question:"Setelah hujan deras atau banjir, dari keran atau sumur di rumahmu keluar 'air yang bening dan bersih'. Apakah boleh meminum air ini begitu saja?",
    choices:["Kalau terlihat bening dan bersih, tidak ada kuman, jadi boleh diminum begitu saja","Jangan pernah meminumnya begitu saja. Air setelah bencana sangat mungkin tercampur kuman dan virus lumpur yang mengerikan dan tak terlihat, jadi selalu 'didihkan kuat-kuat di atas api' sebelum diminum","Dijemur di bawah matahari 10 detik lalu diminum","Menjadi aman kalau dicampur gula"],
    answerIndex:1,
    explanation:"Seperti yang juga kamu pelajari di paket pertama, air setelah hujan deras atau banjir besar tidak boleh sekali-kali diminum begitu saja, sebening dan sebersih apa pun terlihatnya. Ini karena kekuatan ganas banjir sangat mungkin membuat air kotor lama dari dalam tanah dan kotoran ternak mengalir balik dan tercampur ke dalam sumur dan pipa air. Meminumnya begitu saja menimbulkan infeksi berat dan diare, membahayakan nyawamu. Sehaus apa pun kamu, patuhi kebijaksanaan untuk meletakkan air saat bencana di atas api sekali dan mendidihkannya sampai gelembung keluar kuat-kuat, memusnahkan kumannya." },
  { id:59, topic:"Jalan tergenang", emoji:"🦯",
    question:"Setelah hujan deras, sebuah jalan tergenang penuh air dan kamu sama sekali tak bisa melihat tanahnya. Saat kamu benar-benar harus berjalan lewat sini, bagaimana kamu berjalan?",
    choices:["Karena air terasa enak, kamu bertelanjang kaki dan menerjangnya sambil berlari riang","Lubang dalam atau kaca tajam mungkin tersembunyi (tak terlihat) di bawah air, jadi ketuk tanah di kakimu dengan 'tongkat kayu' yang panjang dan kokoh untuk memeriksa, dan maju selangkah demi selangkah","Menutup mata dan berjalan lurus","Minta digendong di punggung orang di belakang untuk menyeberang"],
    answerIndex:1,
    explanation:"Berjalan di jalan yang tanahnya tersembunyi oleh genangan atau banjir sama berbahayanya dengan berjalan sambil menutup mata. Di bawah air mungkin tergeletak pecahan botol pecah dan paku tajam, dan lubang got dalam yang tutupnya terlepas, atau parit dalam tempat tanah tergerus, 'tersembunyi sepenuhnya' menantimu. Kalau kamu menjejakkan kaki sembarangan, kamu jatuh ke dasar lubang lalu terhanyut, atau terluka dalam dan jatuh sakit. Saat kamu benar-benar harus berjalan, selalu pakai sepatu, gunakan tongkat kayu panjang sebagai tongkat penuntun, dan sebelum setiap langkah, ketuk untuk memeriksa apakah 'tanah berikutnya keras dan aman': itulah cara berjalan yang benar yang melindungi nyawamu." },
  { id:60, topic:"Mengamati dan memprediksi", emoji:"🧠",
    question:"Di mana pun kamu berada di dunia, apa 'kekuatan pikiran' terpenting untuk melindungi dengan pasti nyawamu dan keluargamu dari bencana alam yang mengerikan?",
    choices:["Kekuatan untuk terus menunggu di tempat, tanpa melakukan apa-apa, sampai seseorang datang menolong","Kekuatan untuk mengamati baik-baik 'suara, warna, bau, dan gerak makhluk hidup' di alam sekitarmu, memprediksi lebih dahulu bahaya berikutnya, dan bergerak lebih awal dengan kebijaksanaanmu sendiri sebelum keadaan menjadi berbahaya","Kekuatan untuk melatih otot kakimu lebih kuat daripada siapa pun","Kekuatan untuk dengan santai menganggap bahwa kamu tak mungkin tertimpa bahaya"],
    answerIndex:1,
    explanation:"Selamat! Dengan ini selesai 20 soal paket ketiga. Menghadapi bencana alam raksasa yang ditimbulkan Bumi, manusia sama sekali tak bisa menang hanya dengan kekuatan lengan atau kecepatan kaki. Tetapi kita manusia punya 'kebijaksanaan'. Kalau kamu mengamati alam baik-baik, Bumi selalu memberi 'tanda awal' bahwa bahaya sudah dekat: air sungai mengeruh, batu berjatuhan dari gunung, tubuh menggigil, hewan ribut. Kekuatan untuk menyadari ini sedini mungkin, memprediksi di kepalamu 'tempat itu sebentar lagi berbahaya', dan pindah ke tempat aman dengan kakimu sendiri sebelum ada yang menyuruh, itulah jimat terkuat di dunia yang menyelamatkan kamu dan orang-orang yang kamu sayangi." },
  { id:61, topic:"Menghitung Berkelompok", emoji:"🥔",
    question:"Ada 3 karung kentang dengan 10 butir di tiap karung, ditambah 4 kentang lepas. Berapa jumlah kentang seluruhnya?",
    choices:["7 kentang","13 kentang","34 kentang","43 kentang"],
    answerIndex:2,
    explanation:"Saat menghitung, membuat 'kelompok 10' jauh lebih cepat dan lebih sedikit salah daripada menghitung satu per satu. Tiga karung berisi 10 berarti 10, 20, 30 — itu saja sudah 30. Ditambah 4 yang lepas, 30 ditambah 4 menjadi 34. Kebijaksanaan 'sistem basis 10' untuk memahami angka besar dengan benar ini adalah keterampilan dasar yang dipakai setiap hari dalam perdagangan dan perhitungan di seluruh dunia." },
  { id:62, topic:"Pengurangan", emoji:"🐭",
    question:"Kamu punya 25 kacang berharga seluruhnya, tetapi seekor tikus memakan 10 di antaranya. Berapa sisanya?",
    choices:["5 kacang","10 kacang","15 kacang","35 kacang"],
    answerIndex:2,
    explanation:"Untuk menghitung sisa setelah sebagian dari keseluruhan diambil, kita memakai 'pengurangan'. Angka 25 dapat dinyatakan sebagai 'dua kelompok 10 dan 5 lepas'. Bila satu kelompok 10 diambil, tersisa 'satu kelompok 10 dan 5 lepas', yaitu 15. Mampu menghitung dengan benar seberapa banyak makanan atau sumber daya berkurang, dan berapa yang tersisa, adalah kebijaksanaan penting untuk menjalankan hidupmu sesuai rencana." },
  { id:63, topic:"Perkalian", emoji:"🛒",
    question:"Kuis belanja! Kamu ingin membeli 3 buah alat berguna yang harganya 20 koin per buah. Berapa total yang harus kamu bayar?",
    choices:["23 koin","40 koin","60 koin","80 koin"],
    answerIndex:2,
    explanation:"Ketika angka yang sama berulang berkali-kali, kita memakai 'perkalian'. Tiga alat seharga 20 koin per buah berarti 20 ditambahkan tiga kali. 20 ditambah 20 menjadi 40, dan ditambah 20 sekali lagi menjadi 60 seluruhnya. Saat berjual beli di toko, bila kamu tidak memiliki kemampuan menjumlahkan secara cepat dalam kepala ini, kamu bisa ditagih lebih dari seharusnya dan ditipu tanpa kamu sadari. Kemampuan menghitung adalah perisai yang melindungi uangmu sendiri." },
  { id:64, topic:"Pembagian", emoji:"➗",
    question:"Kamu ingin membagi 12 roti pipih secara rata dan tepat kepada 4 anak. Berapa yang diterima tiap anak?",
    choices:["2 per anak","3 per anak","4 per anak","6 per anak"],
    answerIndex:1,
    explanation:"Membagi sesuatu secara adil kepada semua orang adalah ide 'pembagian'. Saat membagikan 12 roti secara rata kepada 4 anak, 2 per anak berarti '2 kali 4 = 8', dan roti masih bersisa. Membagikan 3 per anak berarti '3 kali 4 = 12', yang menghabiskan seluruh roti dengan pas. Kebijaksanaan menghitung angka dengan benar dan membaginya, agar tidak ada yang menerima terlalu banyak sementara yang lain sedih, adalah keterampilan yang sangat penting untuk hidup rukun bersama." },
  { id:65, topic:"Membaca Jam", emoji:"⏰",
    question:"Kuis jam! Ketika jarum panjang mencapai '12', waktunya menjadi tepat pada jamnya. Sekarang jarum panjang menunjuk '9'. Berapa menit lagi sampai tepat pada jamnya?",
    choices:["3 menit lagi","15 menit lagi","30 menit lagi","45 menit lagi"],
    answerIndex:1,
    explanation:"Permukaan jam dibuat berdasarkan aturan bahwa '5 menit' berlalu setiap kali angka maju satu. Agar jarum panjang berpindah dari 9 ke tanda tepat di 12, angka harus maju tiga langkah: 10, 11, 12. Lima menit diulang tiga kali menjadi 5, 10, 15, jadi jawabannya 'dalam 15 menit'. Belajarlah mengurangkan dengan benar memakai angka-angka pada jam, untuk merencanakan berapa lama lagi sampai sebuah janji, atau sampai malam tiba." },
  { id:66, topic:"Membandingkan Berat", emoji:"⚖️",
    question:"Kuis membandingkan berat! Batu A lebih berat daripada batu B. Batu B lebih berat daripada batu C. Di antara ketiga batu ini, mana yang 'paling ringan'?",
    choices:["Batu A","Batu B","Batu C","Semua sama beratnya"],
    answerIndex:2,
    explanation:"Ini adalah teka-teki 'logika' di mana kamu menyusun syarat-syarat dalam kepala untuk mencapai jawaban yang benar. Pertama, 'A lebih berat daripada B', jadi A di atas dan B di bawahnya. Berikutnya, 'B lebih berat daripada C', jadi C di bawah B. Bila disusun berurutan dari atas ke bawah, didapat A (paling berat), B di tengah, dan C (paling ringan) di bawah. Maka yang paling ringan adalah 'batu C'. Latihlah kemampuan menyusun dengan kata-kata dan menilai dengan benar meski benda nyatanya tidak ada di depanmu." },
  { id:67, topic:"Menggabungkan Bentuk", emoji:"📐",
    question:"Kamu punya dua 'segitiga siku-siku' dari kertas. Bila kamu menyatukan sisi panjangnya (sisi miringnya) dengan tepat, bentuk apa yang terbentuk?",
    choices:["Sebuah lingkaran","Bentuk bersisi empat (persegi panjang atau persegi)","Sebuah segilima","Bentuk bintang"],
    answerIndex:1,
    explanation:"Ini adalah kebijaksanaan 'kesadaran ruang' — memindahkan dan menggabungkan bentuk dalam kepala. Segitiga siku-siku yang berujung miring pun bisa berubah menjadi bentuk bersisi empat (persegi panjang atau persegi) dengan semua sudut lurus, bila kamu menyiapkan dua yang sama dan menyatukan sisi panjang miringnya saling berhadapan dengan rapi. Mengetahui ciri-ciri bentuk sangat berguna untuk menata barang dalam kotak tanpa celah yang terbuang, atau untuk merancang fondasi kokoh sebuah bangunan." },
  { id:68, topic:"Membongkar Kebohongan", emoji:"🕵️",
    question:"Teka-teki logika untuk menemukan pembohong. Ada dua anak laki-laki, A dan B. A berkata: 'Aku tidak memakan permen itu.' B berkata: 'A memakan permen itu.' Jika yang dikatakan A itu [benar], apakah B berbohong atau berkata jujur?",
    choices:["B berbohong","B berkata jujur","Keduanya berkata jujur","Tidak bisa dipastikan"],
    answerIndex:0,
    explanation:"Ini adalah teka-teki untuk menemukan pertentangan (bagian yang tidak cocok). Syaratnya menyatakan bahwa 'yang dikatakan A itu benar'. Itu berarti A adalah orang jujur yang memang tidak memakan permen. Namun B berkata persis sebaliknya: 'A memakan permen itu.' Karena B menuduh A yang jujur sebagai pembohong, maka kata-kata B-lah yang menjadi 'kebohongan (kesalahan)'. Kemampuan memilah kata-kata siapa yang benar dan siapa yang bertentangan sangat penting untuk melindungi dirimu." },
  { id:69, topic:"Pola Bilangan", emoji:"🧮",
    question:"Kuis pola. Angka '1, 3, 5, 7, 9' berbaris. Mengikuti aturan ini, angka apa yang muncul setelah 9?",
    choices:["10","11","12","15"],
    answerIndex:1,
    explanation:"Ini adalah latihan otak untuk menemukan pola (deret bilangan) di mana angka bertambah menurut aturan tetap. Bila diperhatikan, dari 1 ke 3 naik '2'. Dari 3 ke 5 juga naik '2'. Jadi barisan angka ini mengikuti aturan (bilangan ganjil) 'naik 2 di tiap langkah'. Untuk mencari angka setelah 9, cukup tambahkan '2' dari aturan itu, jadi 9 ditambah 2 menjadi 11. Kemampuan membaca lebih dulu bagaimana sebuah aturan berubah membuatmu pandai meramalkan masa depan." },
  { id:70, topic:"Teka-teki Memotong", emoji:"🔪",
    question:"Kamu memotong satu batang lurus 'sebanyak 3 kali' dengan pisau. Menjadi berapa potong batang itu terbagi seluruhnya?",
    choices:["2 potong","3 potong","4 potong","5 potong"],
    answerIndex:2,
    explanation:"Ini adalah teka-teki ('soal menanam pohon') untuk membayangkan hubungan antara jumlah potongan dan jumlah bagian yang terbentuk. Memotong satu batang utuh satu kali menghasilkan '2 potong'. Potongan kedua menghasilkan '3 potong'. Dan potongan ketiga menambah satu bagian lagi, menjadi '4 potong' seluruhnya. Ini aturan matematika yang menarik: jumlah potongan selalu 'satu lebih banyak' daripada jumlah pemotongan. Belajarlah menghitung hasilnya dengan benar dalam kepala sebelum merusak benda nyatanya." },
  { id:71, topic:"Kelipatan", emoji:"📊",
    question:"Ada ember-ember untuk menampung air. Ember A menampung air '3 kali' lebih banyak daripada ember B. Ember B berisi 2 liter air. Berapa liter air yang ditampung ember A?",
    choices:["3 liter","5 liter","6 liter","8 liter"],
    answerIndex:2,
    explanation:"'3 kali' suatu angka berarti menggabungkan tiga yang sama — dengan kata lain, 'menambahkannya tiga kali' atau 'mengalikan dengan 3'. Ember B berisi 2 liter, dan A adalah 3 kali itu, jadi ada tiga bagian 2 liter. Menghitung 2 tambah 2 tambah 2, atau 2 kali 3, menghasilkan 6. Dalam keseharian kita sering mengatakan '3 kali beratnya' atau '3 kali luasnya', dan mengetahui konsep kelipatan memungkinkanmu memperkirakan jumlah benda dengan tepat." },
  { id:72, topic:"Urutan dalam Barisan", emoji:"👥",
    question:"Enam anak berdiri dalam satu barisan lurus. Untuk anak yang berada di 'urutan ke-4 dari depan', berapa anak yang ada di belakangnya?",
    choices:["1 anak","2 anak","3 anak","4 anak"],
    answerIndex:1,
    explanation:"Ini adalah teka-teki untuk memahami dengan benar hubungan antara jumlah seluruhnya dan sebuah posisi dalam urutan. Ada 6 anak seluruhnya. Menghitung dari depan, termasuk anak ke-4 itu sendiri, 4 anak telah terpakai sampai sini. Mengurangkan 4 ini dari total 6, tersisa 2. Jadi di belakang anak ke-4 berdiri anak ke-5 dan ke-6 — '2 anak'. Kemampuan memahami posisi dalam barisan sebagai sebuah angka dengan tenang berguna untuk menjaga urutan secara adil dalam masyarakat." },
  { id:73, topic:"Mengukur Panjang", emoji:"📏",
    question:"Kuis pengukuran. Kamu mengukur sebuah meja memakai satuan 'rentang telapak tanganmu yang terbuka, dari ibu jari ke kelingking', dan hasilnya tepat 5 rentang. Apa aturan penting dari cara mengukur ini?",
    choices:["Mengubah rentang tanganmu lebih besar atau lebih kecil setiap kali mengukur","Agar bisa membandingkan panjang dengan benar, selalu mengukur dengan 'rentang yang sama (satuan yang sama)', disambung tanpa celah","Menghitung kira-kira sambil memejamkan mata","Mengukur dengan telapak kaki, bukan tangan"],
    answerIndex:1,
    explanation:"Pada zaman tanpa alat ukur (penggaris), manusia mengukur panjang memakai tangan dan kaki mereka sendiri. Aturan terpenting saat itu adalah 'selalu mempertahankan satuan panjang tetap pada ukuran yang persis sama'. Bila rentang tanganmu berbeda-beda setiap kali, meski kamu menghitung 3 rentang atau 5 rentang, tak seorang pun bisa tahu panjang sebenarnya. Satuan bersama seperti 'sentimeter' lahir di seluruh dunia justru sebagai kebijaksanaan agar semua orang berdagang dengan adil memakai patokan yang sama." },
  { id:74, topic:"Nilai Uang", emoji:"💰",
    question:"Kamu punya satu koin-10 (satu koin yang bernilai 10). Kamu 'menukarnya' dengan sepuluh koin-1 (koin yang masing-masing bernilai 1) dari temanmu. Bagaimana 'nilai total' uang yang kamu pegang (kekuatannya untuk membeli barang) berubah?",
    choices:["Jumlahnya naik menjadi 10 koin, jadi nilainya juga bertambah 10 kali lipat","Hanya bentuknya yang berubah, satu koin terpecah menjadi sepuluh, tetapi nilai total uangnya 'persis sama (tidak berubah)'","Koin-10 lebih besar, jadi kamu rugi dan nilainya turun","Nilai uangnya menjadi nol"],
    answerIndex:1,
    explanation:"Ini kebijaksanaan tentang aturan penting uang: 'kekekalan nilai'. Satu koin-10 dan sepuluh koin-1 sangat berbeda dalam jumlah dan bentuk, tetapi nilai total yang diwakilinya sama, yaitu 10. Hanya karena jumlah koin bertambah, bukan berarti kamu menjadi kaya. Di masyarakat ada orang jahat yang memperlihatkan banyak uang yang dipecah kecil-kecil dan mencoba menipu seorang anak: 'Aku beri semua ini, tukarkan dengan satu koin besar itu.' Jangan tertipu oleh tampilan — milikilah mata yang menghitung nilai yang sebenarnya." },
  { id:75, topic:"Penemuan Nol", emoji:"0️⃣",
    question:"Ada 3 telur dalam keranjang. Kamu memakai ketiganya untuk memasak. Bila kamu menyatakan jumlah telur yang ada di keranjang sekarang dengan sebuah angka, angka berapa itu?",
    choices:["1","2","3","0 (nol)"],
    answerIndex:3,
    explanation:"Salah satu penemuan terbesar dalam matematika adalah angka '0 (nol)'. Nol bukan sekadar berarti tidak ada angka; ia adalah angka istimewa dan bijak yang diciptakan untuk mencatat dan menyatakan, sama seperti angka lain, keadaan 'tidak ada apa pun di sana, kosong'. Kurangi 3 dengan 3 maka sisanya 0. Berkat nol ini, kita bisa memberi tahu dengan tepat kepada teman yang jauh, lewat tulisan atau angka, suatu krisis seperti 'makanan benar-benar habis' atau 'tidak ada muatan sama sekali', dan memanggil bantuan." },
  { id:76, topic:"Mengelompokkan", emoji:"🐶",
    question:"Kuis mengelompokkan kata. 'Anjing, kucing, burung, kadal' — ke dalam kelompok besar mana mereka semua termasuk (digolongkan)?",
    choices:["Kelompok tumbuhan","Kelompok hewan","Kelompok ikan","Kelompok manusia"],
    answerIndex:1,
    explanation:"Ini adalah logika 'penggolongan (mengelompokkan berdasarkan ciri bersama)'. Anjing, kucing, burung, dan kadal masing-masing berbeda bentuk dan cara hidupnya, tetapi mereka memiliki ciri besar bersama: 'makhluk hidup yang bergerak sendiri dan memakan makanan'. Karena itu, semuanya termasuk dalam ruang besar bernama 'hewan'. Menata di kepala banyak informasi dan alat di dunia — ke dalam kelompok besar dan jenis yang lebih rinci — adalah senjata berpikir yang ampuh untuk cepat memahami inti dari segala hal." },
  { id:77, topic:"Menghitung Mundur", emoji:"⏪",
    question:"Ada suatu angka (angka kuis). Ketika '5' ditambahkan padanya, jawabannya menjadi '12'. Berapa angka semula?",
    choices:["5","7","12","17"],
    answerIndex:1,
    explanation:"Ini teka-teki 'menghitung mundur', di mana kamu memutar balik waktu dari hasil untuk menemukan sebab semula. Jika menambah 5 pada suatu angka menghasilkan 12, maka 'memutar balik dan mengurangkan 5 yang ditambahkan tadi' dari 12 akhir akan mengungkap angka semula. 12 dikurangi 5 menjadi 7. Ketika muncul masalah dalam hidup, 'kemampuan memutar balik waktu dari hasil ke sebab' ini memungkinkanmu dengan cerdik menemukan di mana kamu keliru, atau apa yang merusak sebuah alat, lalu memperbaikinya." },
  { id:78, topic:"Belanja dengan Anggaran", emoji:"🛍️",
    question:"Kuis belanja! Kamu punya '30 koin'. Toko menjual kentang seharga 10 koin, tomat 15 koin, dan ikan 20 koin. Untuk membeli tepat '2 jenis makanan' dengan uang yang kamu punya, dua mana yang harus kamu pilih?",
    choices:["Kentang dan tomat","Tomat dan ikan","Kentang dan ikan","Tidak ada pasangan dua yang bisa dibeli"],
    answerIndex:2,
    explanation:"Ini kuis berpikir di mana kamu menemukan kombinasi yang memenuhi syarat terbatas (anggaran 30 koin, tepat 2 jenis). Jumlahkan tiap harga. Kentang 10 koin tambah tomat 15 koin menjadi 25 koin, kurang dari 30, dan uang bersisa. Tomat 15 koin tambah ikan 20 koin menjadi 35 koin, yang melebihi 30 dan tidak bisa dibeli. Kentang 10 koin tambah ikan 20 koin menjadi tepat 30 koin, yang persis sama dengan uang yang kamu punya. Maka jawaban yang benar adalah kombinasi kentang dan ikan. Pakailah kemampuan menggabungkan beberapa angka dalam kepala dan merencanakan agar tidak melampaui anggaranmu." },
  { id:79, topic:"Jumlahnya Tetap Sama", emoji:"🥤",
    question:"Kamu menuang seluruh 'air' dari gelas tinggi dan sempit ke piring datar dan lebar. Permukaan air melebar, tetapi bagaimana 'jumlah air seluruhnya (volumenya)' berubah?",
    choices:["Piring lebih lebar, jadi jumlah airnya juga menjadi dua kali lipat","Gelas tadi lebih tinggi, jadi jumlah airnya berkurang","Meski bentuk wadahnya berubah, karena kamu tidak menumpahkan apa pun, jumlah airnya 'persis sama (tidak berubah)'","Airnya hilang semua"],
    answerIndex:2,
    explanation:"Ini kebijaksanaan yang sangat penting tentang 'kekekalan' dalam sains dan matematika. Meski sebuah bentuk menjadi tinggi dan ramping, atau melebar datar dan luas, selama kamu tidak menambah air baru dari luar maupun menumpahkan, jumlah total zat di dalamnya 'pasti sama' dan tidak berubah. Di masyarakat ada orang yang menuang jus ke wadah dangkal yang tampak lebar dan mencoba menipumu lewat tampilan: 'Lihat, jadi banyak sekali, untung sekali!' Jangan tertipu oleh bentuk; milikilah mata yang menembus ke inti isinya." },
  { id:80, topic:"Berpikir tentang Peluang", emoji:"🔴",
    question:"Kuis kepastian. Ada kantong yang benar-benar tidak tembus pandang berisi hanya 5 'batu merah'. Ketika kamu memasukkan tangan dan mengambil 1 batu, bisakah keluar 'batu biru'?",
    choices:["Kadang satu bisa keluar secara kebetulan","Karena kantong hanya berisi batu merah, keluarnya batu biru itu '100% mustahil (peluang nol)'","Kalau kamu mengguncang kantong sekuat tenaga, satu akan keluar","Pada malam hari ia berubah menjadi batu biru"],
    answerIndex:1,
    explanation:"Ini kuis untuk berpikir secara logis tentang kepastian (peluang) terjadinya sesuatu. Kantong itu hanya berisi 'batu merah' sejak awal. Kecuali terjadi sihir, tidak ada sebab apa pun bagi 'batu biru' yang tidak ada di dalam untuk keluar. Maka peluang keluarnya batu biru adalah '100% mustahil' — itulah jawabannya. Di dunia ada orang yang mencoba menipu orang lain dengan kebohongan seperti 'kalau kamu berdoa, makanan akan muncul dari ketiadaan'. Simpanlah dalam otakmu logika dingin sains: yang tak punya sebab tak akan pernah terjadi sebagai hasil." },
  { id:81, topic:"Kerja dan Pembagian Tugas", emoji:"👷",
    question:"Apa alasan utama orang dewasa di seluruh dunia mengerjakan berbagai 'pekerjaan (kerja)' — mengolah ladang, mendirikan bangunan, membuat alat?",
    choices:["Agar satu orang saja bisa hidup mewah dan menyombongkan diri","Karena seorang manusia tidak bisa bertahan hidup sendirian; dengan masing-masing mengerjakan pekerjaan berbeda dan saling membantu (pembagian kerja), seluruh masyarakat bisa hidup dengan aman","Hanya karena ingin menggerakkan badan dan bermain","Mereka bergerak hanya karena diperintah seseorang, tanpa pilihan"],
    answerIndex:1,
    explanation:"Manusia adalah makhluk lemah, tanpa taring tajam seperti singa, yang akan mati kedinginan tanpa pakaian. Lebih lagi, mustahil bagi satu orang membangun rumahnya sendiri, menanam gandumnya sendiri, dan membuat obatnya sendiri — waktunya tidak cukup. Karena itu umat manusia menemukan kebijaksanaan sosial 'pembagian kerja', di mana semua orang membagi-bagi pekerjaan yang berbeda. Tukang kayu membangun rumah, petani menanam makanan, dokter menyembuhkan penyakit. Inti pekerjaan adalah menyelesaikan kesulitan orang lain di dalam masyarakat dan dengan lembut menopang kehidupan satu sama lain melalui barang dan jasa." },
  { id:82, topic:"Awal Mula Uang", emoji:"🐚",
    question:"Apa manfaat terbesar ketika manusia purba berhenti menukar barang secara langsung dan mulai memakai 'uang (mata uang)' dari kerang atau logam?",
    choices:["Karena memiliki uang membuat pencuri berhenti menyerangmu","Karena bahkan di antara 'orang-orang yang ingin menukar barang berbeda', menyelipkan uang di tengah memungkinkan bertukar dengan adil dan lancar kapan saja demi yang kamu inginkan","Karena uang menjadi gizi bila dimakan","Karena uang berserakan di mana-mana tanpa habis"],
    answerIndex:1,
    explanation:"Dalam kehidupan 'barter', meski kamu ingin menukar ikanmu dengan pakaian seseorang, pertukaran gagal jika orang itu tidak menginginkan ikan. Lagi pula, ikan cepat busuk, jadi nilainya tidak bisa disimpan. Karena itu umat manusia membuat alat kepercayaan yang nilainya diakui semua orang: 'uang (mata uang)'. Sekali ikan diubah menjadi uang, kamu bisa menyimpannya tanpa membusuk, dan nanti membeli pakaian atau obat di kota lain, kapan pun kamu perlu. Uang adalah kebijaksanaan luar biasa, ditemukan agar orang-orang di dunia saling membantu dengan lancar tanpa kerepotan." },
  { id:83, topic:"Janji Bersama", emoji:"📜",
    question:"Di lapangan atau jalan yang dipakai bersama, untuk apa ada 'aturan (janji masyarakat)' seperti 'jangan membuang sampah' dan 'menjaga giliran'?",
    choices:["Untuk memarahi anak-anak dan merampas kebebasan mereka","Karena ketika semua orang mematuhi aturan, pertengkaran dan kecelakaan dapat dicegah, dan semua bisa hidup setara, dengan lembut dan aman","Untuk menutup lapangan agar tidak seorang pun memakainya","Untuk menguntungkan hanya orang penting tertentu"],
    answerIndex:1,
    explanation:"Aturan dan hukum (janji) tidak dibuat untuk mengikat seseorang dan membuatnya tidak bebas. Apa yang akan terjadi bila tidak ada aturan sama sekali dan semua orang bertindak 'seenaknya'? Lapangan akan penuh sampah dan menimbulkan penyakit, kereta dan kendaraan akan bertabrakan di jalan, dan yang kuat akan merampas makanan yang lemah — dunia kekerasan yang menakutkan. Aturan adalah 'kontrak lembut yang disepakati semua orang' untuk melindungi keselamatan semua. Mematuhi aturan dengan benar langsung berkaitan dengan melindungi kebebasan dan keselamatanmu sendiri." },
  { id:84, topic:"Siklus Air", emoji:"🔄",
    question:"Setelah 'air hujan' jatuh dari langit dan meresap ke tanah, perjalanan seperti apa yang ditempuhnya untuk kembali ke langit lagi?",
    choices:["Ia tergenang di dasar tanah dan tidak pernah bergerak lagi","Ia berkumpul menjadi sungai dan mengalir ke laut, menguap karena panas matahari menjadi awan, lalu jatuh lagi sebagai hujan (siklus air)","Ia terbang lurus ke luar angkasa","Manusia meminumnya habis dan selesai"],
    answerIndex:1,
    explanation:"Seluruh air di Bumi, sejak ratusan juta tahun lalu, terus berkeliling ke seluruh planet sambil berubah bentuk. Ini disebut 'siklus' air. Hujan yang jatuh di gunung membentuk sungai, pergi ke laut sambil menghidupi makhluk hidup, dihangatkan matahari menjadi uap air tak terlihat yang naik ke langit, mendingin menjadi awan, dan jatuh lagi sebagai hujan. Air yang kita minum hari ini adalah harta planet yang sama dengan yang diminum dinosaurus dahulu kala. Melindungi mekanisme alam berupa air bersih yang berputar dari pencemaran berkaitan dengan melindungi kehidupan seluruh umat manusia." },
  { id:85, topic:"Tumbuhan dan Oksigen", emoji:"🌳",
    question:"Banyaknya 'pohon dan rumput (tumbuhan)' di hutan — pekerjaan luar biasa apa yang mereka lakukan agar kita, manusia, dan makhluk hidup lain bisa hidup?",
    choices:["Pekerjaan menggelapkan tanah dan membuatnya dingin","Memakai cahaya matahari dan air, pekerjaan menciptakan di udara 'oksigen bersih' yang mutlak dibutuhkan manusia dan hewan untuk bernapas","Pekerjaan menghentikan seluruh angin dan memanaskan Bumi","Mereka tidak melakukan apa-apa"],
    answerIndex:1,
    explanation:"Manusia dan hewan menghirup 'oksigen' yang terkandung di udara dan mengembuskan 'karbon dioksida' sebagai gantinya. Bila tidak ada tumbuhan di Bumi, oksigen di udara akan segera habis dan semua makhluk hidup akan sesak napas dan mati. Pohon dan rumput hutan memakai cahaya matahari untuk menghirup karbon dioksida dan terus menghasilkan tanpa henti, setiap hari, 'oksigen' segar yang kita butuhkan untuk hidup. Lebih lagi, akar tumbuhan mencengkeram tanah dengan kuat dan juga melakukan pekerjaan mencegah tanah longsor di gunung. Melindungi hutan adalah melindungi pabrik udara Bumi." },
  { id:86, topic:"Penyerbukan dan Serangga", emoji:"🦋",
    question:"Serangga seperti 'lebah dan kupu-kupu' yang datang ke bunga — peran penting apa yang mereka jalankan untuk membantu tumbuhan meninggalkan keturunan?",
    choices:["Peran mencabuti semua daun bunga dan membuatnya layu","Sebagai ganti mengisap madu bunga, peran menempelkan 'serbuk sari' ke kaki dan tubuh lalu membawanya ke bunga yang jauh, membantu terbentuknya buah dan biji (penyerbukan)","Peran membuat bunga marah agar tumbuh duri","Mereka hanya bermain dan tidak berguna sama sekali"],
    answerIndex:1,
    explanation:"Tumbuhan, yang tidak bisa bergerak selangkah pun dari tanah, tidak bisa memperbanyak jenisnya sendiri (biji). Di sinilah serangga seperti lebah dan kupu-kupu berperan besar. Mereka terbang dari bunga ke bunga untuk memakan madu yang lezat, dan ketika 'serbuk sari' yang menempel di tubuhnya terbawa ke bunga lain, tumbuhan akhirnya bisa dengan aman membentuk 'biji dan buah'. Ini disebut 'penyerbukan'. Bila serangga lenyap, tumbuhan dunia tidak bisa berbuah, dan hutan serta ladang akan musnah. Di alam, semua hidup saling membantu tanpa menyadarinya." },
  { id:87, topic:"Membuang Sampah Sembarangan", emoji:"🗑️",
    question:"Apa yang terjadi bila kamu membuang sisa makananmu dan alat yang tidak kamu pakai lagi (sampah) langsung ke sungai atau ke tanah?",
    choices:["Sampah larut dengan sendirinya dan berubah menjadi uang","Air dan tanah menjadi kotor, kuman dan racun berbahaya menyebar, ikan sungai dan hewan hutan mati, dan berputar kembali, bahkan air minum dan makanan manusia pun menjadi berbahaya","Tanah menjadi lebih kokoh dan lebih mudah membangun rumah","Tidak ada yang berubah"],
    answerIndex:1,
    explanation:"Membuang sampahmu sembarangan di dekat situ sama saja dengan menebar racun di dalam rumah tempatmu tinggal sendiri. Plastik dan sampah tertentu tidak hilang oleh kekuatan alam meski sudah ratusan tahun. Terbawa hujan, ia mencemari sungai dan laut; ikan yang memakannya jatuh sakit; dan ketika manusia memakan ikan itu, pada akhirnya ia kembali sebagai 'racun mematikan' ke tubuhmu sendiri dan kesehatan anak-anakmu. Seluruh dunia saling terhubung. Bertanggung jawab merapikan dan mengelola dengan benar apa yang telah kamu pakai adalah kelembutan masyarakat yang melindungi kehidupan masa depan." },
  { id:88, topic:"Memperbaiki dan Memakai Lagi", emoji:"🔨",
    question:"Ketika kapak, pisau, atau pakaian berharga di rumah rusak atau robek sedikit, mana tanggapan yang paling bijak?",
    choices:["Segera membuangnya dan merebut yang baru dari seseorang","Memakai kebijaksanaanmu untuk 'memperbaiki (menambal)', dan terus memakai satu alat itu dengan hati-hati untuk waktu yang lama","Memaksa memakainya dalam keadaan rusak dan terluka parah","Berpura-pura tidak melihatnya dan membiarkannya"],
    answerIndex:1,
    explanation:"Untuk membuat alat, perlu memakai banyak 'sumber daya' berharga Bumi, seperti kayu, besi, dan serat tumbuhan. Itu tidak tak terbatas. Bila kamu membuang barang begitu rusak sedikit, sumber daya dunia akan habis dan tak seorang pun bisa membuat alat lagi. Kebijaksanaan menakjubkan umat manusia telah mengembangkan keterampilan 'memperbaiki dan memakai lagi' barang yang rusak. Memperbaiki alat dan memakainya dengan hati-hati untuk waktu lama adalah keterampilan hidup penting untuk melindungi sumber daya Bumi, mengurangi pengeluaran sia-sia, dan hidup dengan cerdas serta mandiri." },
  { id:89, topic:"Menerima Perbedaan", emoji:"🤝",
    question:"Dunia penuh dengan orang yang 'bahasa', 'warna kulit', dan 'rumah tempat tinggal'-nya sama sekali berbeda darimu. Apa sikap hati yang paling penting untuk akur dan bekerja sama dengan mereka?",
    choices:["Mencari di mana mereka berbeda darimu, lalu menindas atau mengucilkan mereka","Meski rupa dan bahasa berbeda, mengakui perbedaan satu sama lain sebagai sesama 'manusia yang memiliki nyawa berharga' dan saling memperlakukan dengan lembut dan penuh hormat","Menyombongkan dengan keras bahwa kelompokmu sendiri lebih unggul","Karena takut, menyerang semua orang seakan mereka musuh"],
    answerIndex:1,
    explanation:"Tergantung negara tempat lahir dan lingkungan tempat tumbuh, orang sama sekali berbeda dalam bahasa yang dipakai, makanan yang dimakan, dan budaya yang dijunjung. Tetapi mana yang lebih unggul atau mana yang buruk — itu tidak pernah ada. Menindas atau bertengkar dengan seseorang hanya karena ia 'berbeda' adalah tindakan paling bodoh, yang mencabik-cabik masyarakat dan membuat semua orang tidak bahagia. Perbedaan adalah kesempatan menakjubkan untuk belajar kebijaksanaan baru. Mengakui perbedaan satu sama lain, dan memiliki hati yang lembut yang menolong melintasi batas negara saat orang lain kesulitan, adalah langkah pertama untuk mengakhiri perang dan kemiskinan di dunia." },
  { id:90, topic:"Sumber Daya Bersama", emoji:"⛲",
    question:"Mengapa kamu tidak boleh menguasai sendiri, atau mengotori, 'sumur bersama' atau 'air bersih' milik desa?",
    choices:["Karena air sumur terkejut dan menjadi kering","Karena merampas sumber daya milik semua (barang publik) membuat orang lain tidak bisa minum dan kehilangan nyawa, dan mekanisme kerja sama seluruh masyarakat menjadi rusak","Karena ada harta karun tersembunyi di dalam sumur","Tidak ada alasan tertentu"],
    answerIndex:1,
    explanation:"Harta bersama yang dipakai semua orang untuk hidup — seperti sungai, hutan, dan sumur — disebut 'barang publik'. Bila seseorang yang kuat menguasainya atau mengotorinya seenaknya, banyak orang lemah yang tidak bisa bertahan hidup bermunculan, dan keseimbangan seluruh desa atau kota runtuh dan semua binasa. Yang milik semua dipakai sedikit demi sedikit, dengan adil dan hati-hati, menurut aturan yang diputuskan semua orang bersama. Masyarakat tempat kebijaksanaan 'berbagi (bantuan publik dan gotong royong)' ini berjalan benar-benar kaya: dunia yang lembut (kesejahteraan) tempat semua orang bisa hidup lama dengan tenang." },
  { id:91, topic:"Belajar dari Sejarah", emoji:"📚",
    question:"Apa makna mempelajari, lewat buku dan cerita, peristiwa zaman dahulu dan 'catatan banjir besar' yang dialami kakek-nenek?",
    choices:["Untuk mendengar cerita lama yang menakutkan dan hanya hidup gemetar ketakutan setiap hari","Untuk mempelajari 'kebijaksanaan sejarah' — kegagalan apa yang dibuat orang masa lalu dan bagaimana mereka mengatasi bahaya — dan melindungi kehidupan masa depanmu dengan aman","Untuk menjelek-jelekkan orang masa lalu","Untuk berpura-pura belajar dengan membaca buku"],
    answerIndex:1,
    explanation:"Makna sejati mempelajari sejarah bukan menghafal nama orang zaman dahulu. Itu adalah menerima 'pesan hidup-mati (data pengalaman) yang ditinggalkan manusia masa lalu untuk kita'. Bila orang dulu meninggalkan catatan yang berbunyi 'sekali dalam seratus tahun sungai ini meluap sampai ketinggian batu itu, jadi jangan membangun rumah di sini', kita bisa terhindar dari membangun di tempat yang sama dan nyawa kita terselamatkan. Sejarah adalah panduan terkuat yang dibangun umat manusia dari puluhan ribu kegagalan. Pelajari kebijaksanaan para pendahulu dan hindari dengan cerdik krisis masa depan." },
  { id:92, topic:"Perjalanan Makanan", emoji:"🚜",
    question:"'Makanan' yang kamu makan di hadapanmu setiap hari, seperti nasi dan roti — perjalanan seperti apa yang telah ditempuhnya untuk sampai ke mulutmu?",
    choices:["Seseorang di suatu tempat membacakan sihir dan memunculkannya di piring dalam sekejap","Lewat 'kerja' banyak orang: petani mengolah ladang setiap hari, orang lain membawanya dari jauh, pedagang menjualnya, dan seseorang di rumah memasaknya","Ia menyembul dari tanah dengan sendirinya","Ia jatuh dari luar angkasa"],
    answerIndex:1,
    explanation:"Di balik makanan yang kamu lihat ada 'estafet ratusan orang (kerja)' yang tak terlihat. Petani yang mengolah tanah, menabur benih, dan membesarkannya sambil mencemaskan cuaca setiap hari. Orang yang memuatnya di gerobak berat atau truk dan membawanya menempuh jalan jauh. Orang yang menjualnya dengan adil di pasar. Dan orang yang memasaknya dengan sepenuh hati untukmu. Menghargai makanan berarti berterima kasih dan menghormati waktu dan usaha (kekuatan hidup) setiap orang itu. Tumbuhkan hati yang lembut yang makan dengan syukur dan tidak menyia-nyiakan apa pun." },
  { id:93, topic:"Berbagi Bahaya", emoji:"🚧",
    question:"Di hutan atau jalan, kamu menemukan 'tempat berbahaya di mana tanah longsor parah, sehingga masuk ke situ berarti jatuh ke lubang dan terluka parah'. Apa hal pertama yang harus dilakukan?",
    choices:["Karena cukup kamu sendiri yang tahu, pergi diam-diam","Agar teman atau warga yang datang kemudian tidak jatuh dan terluka, memasang 'penanda (penghalang)' dengan ranting besar, atau segera memberi tahu orang dewasa dan orang di sekitar untuk berbagi bahaya itu","Melempar banyak batu ke dalam lubang","Bermain petak umpet di dekat lubang"],
    answerIndex:1,
    explanation:"Memberitahukan kepada seluruh masyarakat suatu bahaya yang kamu temukan, bukan hanya menyelamatkan diri sendiri, disebut 'berbagi risiko'. Bila kamu pergi diam-diam, anak kecil yang datang berlari kemudian, atau kakek yang berjalan di jalan pada malam hari, bisa jatuh ke lubang tanpa sadar dan menderita luka yang mematikan. Memberitahukan bahaya kepada orang lain adalah tindakan kesejahteraan yang menakjubkan yang 'secara tidak langsung menyelamatkan nyawa orang lain' dari kecelakaan masa depan yang belum terjadi. Jadilah pemimpin yang lembut yang memakai kebijaksanaan untuk semua." },
  { id:94, topic:"Daur Ulang", emoji:"♻️",
    question:"Apa nama sistem mengubah kain lap lusuh, alat yang rusak, dan wadah plastik — alih-alih membakar atau menguburnya sebagai sampah — menjadi bahan untuk alat baru, lahir kembali?",
    choices:["Membuang sampah sembarangan","Daur ulang (pemanfaatan kembali sumber daya)","Barter","Fotosintesis"],
    answerIndex:1,
    explanation:"Alih-alih sekadar membuang sampah bekas ke tempat sampah, keterampilan melelehkannya lagi atau memecahnya menjadi potongan kecil dan mengubahnya, dari nol, menjadi 'bahan' untuk pakaian, ember, dan alat baru disebut 'daur ulang (pemanfaatan kembali sumber daya)'. Bila dipakai dengan baik, daur ulang membuatmu tak perlu lagi mengeruk gunung-gunung Bumi untuk bahan baru, sehingga kamu bisa mempertahankan kehidupan yang makmur selamanya tanpa melukai planet. Ini kebijaksanaan mutakhir untuk menghargai sumber daya alam dan membangun dunia yang berkelanjutan (bertahan lama)." },
  { id:95, topic:"Cara Kerja Musim", emoji:"🌎",
    question:"Di Bumi, musim hangat saat tumbuhan tumbuh dan musim dingin saat salju turun (pergantian musim) berputar setiap tahun menurut aturan tetap. Mengapa?",
    choices:["Karena ketika Bumi berputar mengelilingi Matahari selama setahun, poros Bumi miring sedikit ke samping","Karena Matahari mengubah kecerahannya setiap hari sesuka hati","Karena awan kejar-kejaran terus mengelilingi Bumi","Karena dewa musim mengubahnya sesuka hati"],
    answerIndex:0,
    explanation:"Bumi memiliki pergantian musim seperti 'semi, panas, gugur, dingin', dan ini punya sebab 100% ilmiah. Bintang bundar bernama Bumi mengelilingi Matahari satu kali selama setahun (revolusi), dan ketika melakukannya, kepala Bumi (porosnya) tetap miring 'sedikit ke samping'. Karena itu, sepanjang perjalanan, muncul bergantian 'masa ketika banyak cahaya matahari mengenai (musim panas)' dan 'masa ketika cahaya datang miring sehingga sedikit mengenai (musim dingin)', sehingga musim berputar sesuai kalender. Pahami aturan mutlak alam semesta dan manfaatkan untuk merencanakan hidupmu." },
  { id:96, topic:"Ternak dan Hidup Bersama", emoji:"🐄",
    question:"Mengapa manusia purba menjinakkan sapi, kuda, anjing, dan hewan liar lainnya untuk hidup bersama sebagai 'ternak'?",
    choices:["Untuk berlari dan bermain dengan hewan","Untuk saling membantu: meminta mereka menarik gerobak berat yang tak bisa digerakkan manusia dan berbagi susu serta bulunya, sebagai ganti memberi hewan makanan dan rumah yang aman (hidup bersama)","Untuk mengurung hewan dalam kamar dan menyombongi mereka","Tidak ada alasan apa pun"],
    answerIndex:1,
    explanation:"Sistem 'ternak', di mana manusia memelihara hewan dan hidup berdampingan, adalah kebijaksanaan 'hidup bersama (simbiosis)' yang menakjubkan untuk bertahan hidup di alam besar dengan saling melengkapi kelemahan. Dengan meminjam tenaga dahsyat kuda dan sapi, manusia bisa mengolah ladang luas dalam sekejap dan mengangkut ratusan kilo barang. Sebagai gantinya, manusia membangun kandang aman tempat hewan tidak diserang pemangsa liar, dan menyiapkan makanan lezat serta air setiap hari untuk merawat nyawa mereka. Kasih sayang terhadap makhluk hidup dan kebijaksanaan merawatnya telah memperkaya kehidupan manusia." },
  { id:97, topic:"Menyatukan Tenaga", emoji:"🗿",
    question:"Sebuah 'batu raksasa' yang tidak bergeser semilimeter pun betapapun kuat satu orang mendorong menghalangi jalan. Apa cara paling bijak untuk memindahkan batu ini?",
    choices:["Memukuli batu itu sendirian setiap hari sambil menangis","Mengumpulkan banyak kawan, memakai tuas panjang, dan membuat semua menyatukan tenaga pada saat yang sama dengan satu aba-aba 'Satu, dua, tarik!' (bekerja bersama)","Menunggu diam sampai batu menyingkir sendiri","Berteriak dan membentak batu itu"],
    answerIndex:1,
    explanation:"Tenaga satu orang punya batas fisik yang mutlak. Tetapi kekuatan sejati manusia bukan pada tebalnya otot, melainkan pada kemampuan otak untuk 'menyatukan tenaga (bekerja sama)' dengan manusia lain. Sepuluh orang yang mendorong terpisah-pisah tidak bisa menggerakkan batu, tetapi ketika semua memusatkan energi pada 'saat yang persis sama' mengikuti aba-aba 'Satu, dua, tarik!' (menyelaraskan) dan menerapkan asas tuas, batu raksasa yang mustahil bagi satu orang berguling dan bergerak dengan mudah secara mengejutkan. Kerja sama adalah kekuatan terbesar umat manusia." },
  { id:98, topic:"Kegagalan adalah Pelajaran", emoji:"🎯",
    question:"Di tengah pekerjaan, belajar, atau kuis, kamu keliru — sebuah 'kegagalan'. Saat itu, mana cara memakai hati yang benar agar kamu paling berkembang?",
    choices:["Berbohong bahwa kamu tidak mungkin gagal, dan menyembunyikan kesalahan","Berpikir 'kegagalan adalah kesempatan belajar terbaik dan terjadi pada siapa saja', memikirkan mengapa kamu keliru, dan memanfaatkannya lain kali","Menyerah dengan menganggap dirimu orang tak berguna dan tidak pernah mencoba lagi","Marah dan berkata bahwa kegagalan itu salah orang lain"],
    answerIndex:1,
    explanation:"Dalam hidup, berbuat keliru dan gagal sama sekali tidak memalukan maupun buruk. Bahkan ilmuwan dan dokter paling bijak di dunia membuat puluhan ribu kegagalan berulang-ulang untuk mencapai penemuan mereka yang menakjubkan. Yang paling sia-sia adalah menyembunyikan kegagalan, atau menyalahkan orang lain, lalu berhenti belajar. Pernah gagal berarti kamu memperoleh satu data berharga: 'cara ini tidak berhasil'. Temukan dengan tenang penyebabnya, dan tumbuhkan kemampuan menyusun langkah berikutnya (ketangguhan)." },
  { id:99, topic:"Memeriksa Desas-desus", emoji:"🔍",
    question:"Kamu mendengar desas-desus dari seseorang: 'Katanya di sungai itu menyembur air ajaib yang menyembuhkan penyakit apa pun dalam sekejap.' Apa yang kamu lakukan?",
    choices:["Karena ceritanya menakjubkan, langsung memercayainya dan minum banyak air itu","Tidak memercayai desas-desus 100% begitu saja; memakai pengetahuan orang dewasa dan buku tepercaya untuk memeriksa sendiri dengan saksama apakah ada bukti ilmiah yang nyata","Menyebarkan kebohongan kepada semua teman bahwa mereka akan mati bila tidak cepat meminumnya","Menjadi takut dan tidak pernah keluar kamar lagi"],
    answerIndex:1,
    explanation:"Masyarakat penuh dengan desas-desus tanpa dasar (tanpa bukti) dan informasi buruk (disinformasi) yang sengaja disebar untuk mencemaskan orang atau menipu agar uangnya diambil. Bertindak dengan menelan mentah-mentah kata-kata 100% sama berbahayanya dengan naik mobil tanpa rem. Setiap kali sesuatu terasa janggal atau aneh, selalu berhentilah sejenak dan berpikir: 'Apakah itu benar? Adakah bukti yang kuat?' Kebijaksanaan memeriksa fakta dengan data buku dan dengan orang tepercaya yang berpengalaman (melek media) melindungimu dari jebakan." },
  { id:100, topic:"Perisai Kebijaksanaan", emoji:"🛡️",
    question:"Di aplikasi 'Wise World 2' ini, kamu telah belajar begitu banyak tentang cara kerja tubuh, hukum alam, dan keterhubungan masyarakat. Apa 'tujuan yang sebenarnya'?",
    choices:["Mengumpulkan poin pengalaman permainan (EXP) dan menjadi orang paling penting di dunia","Menyimpan di kepalamu 'perisai kebijaksanaan tertinggi dan terkuat', agar di lingkungan apa pun kamu tidak tertipu, hidup dengan cerdas dan mandiri, dan — sambil melindungi hak asasi dan nyawa orang lain — membangun dengan tanganmu sendiri 'dunia yang lembut dan aman' untuk ditinggali","Menguasai semua uang dan memerintah orang lain agar menurutimu","Menjawab benar semua pertanyaan dan menamatkan permainan"],
    answerIndex:1,
    explanation:"Luar biasa! Kuis ke-100 yang berkesan kini selesai. Semua 'kebijaksanaan' yang kamu pelajari di aplikasi ini bukan untuk mengalahkan orang lain dan menyombong, bukan pula untuk satu orang saja hidup mewah. Itu agar, di mana pun kamu berada di dunia — bahkan di lingkungan keras tanpa orang dewasa yang menolong — kamu bisa berpikir secara ilmiah dengan pikiranmu sendiri untuk melindungi nyawamu, dan bertahan hidup secara mandiri tanpa tertipu orang jahat (pemberdayaan). Dan itu adalah cahaya untuk memakai pengetahuan bijak itu guna menolong orang-orang yang kesulitan di sekitarmu, dan — melintasi batas negara dan bahasa — terus memutar sendiri, bersama semua orang, 'perekonomian dan dunia kesejahteraan yang lembut dan aman'. Kebijaksanaan kokoh yang kamu pelajari akan melindungi hidupmu mulai sekarang dan menjadi jimat yang dengan lembut menerangi masa depan dunia. Semua orang di seluruh dunia dengan sepenuh hati menyemangati keberhasilan perjalanan belajarmu!" }
];
